export const RESOURCE_DATA_RAW = [
    // General
    { category: 'General', name: 'Resource group', provider: 'Microsoft.Resources/resourceGroups', abbrev: 'rg', maxLength: 90, scope: 'Subscription', chars: 'a-z, A-Z, 0-9, -, _, (), .', desc: 'Logical container that groups Azure resources sharing the same lifecycle, permissions, and policies. Enables unified deployment via ARM/Bicep templates with atomic operations and RBAC inheritance.', longDesc: 'Logical container that groups Azure resources sharing the same lifecycle, permissions, and policies. Enables unified deployment via ARM/Bicep templates with atomic operations and RBAC inheritance. Resource groups are the primary unit for access control, cost management, and resource lifecycle management. Tags applied at the group level can be inherited by child resources via Azure Policy, enabling consistent cost allocation and governance. Deleting a resource group removes all contained resources in a single operation.', bestPractice: 'Name pattern: rg-{workload}-{env}-{region}. Group resources by solution lifecycle; include env and region for quick identification.', namingGuidance: 'Name pattern: rg-{workload}-{env}-{region}. Group resources by solution lifecycle; include environment and region for quick identification in the portal. Avoid generic names like "rg-dev" — instead use descriptive workload names aligned to your application or service, for example rg-payments-prod-uks. The CAF recommends one resource group per application tier per environment.', learnUrl: 'https://learn.microsoft.com/azure/azure-resource-manager/management/overview' },
    { category: 'General', name: 'Management group', provider: 'Microsoft.Management/managementGroups', abbrev: 'mg', maxLength: 90, scope: 'Tenant', chars: 'a-z, A-Z, 0-9, -, _, (), .', desc: 'Hierarchical container organizing subscriptions for enterprise-scale governance. Supports up to 6 levels of nesting with inherited Azure Policy and RBAC assignments.', longDesc: 'Hierarchical container that organises subscriptions into a governance structure for enterprise-scale management. Supports up to 6 levels of nesting below the root tenant group, with Azure Policy and RBAC assignments inherited downward through the tree. Management groups are the backbone of the Cloud Adoption Framework (CAF) landing zone architecture — separating Platform (identity, connectivity, management) from Landing Zones (production, dev/test) and Sandbox. Each management group can contain subscriptions and child management groups, enabling consistent governance at scale. Moving subscriptions between groups automatically applies the target group\'s policies.', bestPractice: 'Name pattern: mg-{scope}-{purpose}. Use descriptive names like mg-platform, mg-landingzones, mg-sandbox for CAF alignment.', namingGuidance: 'Name pattern: mg-{scope}-{purpose}. Management group names should align with your CAF landing zone hierarchy — use names like mg-platform, mg-landingzones-prod, and mg-sandbox that clearly communicate the group\'s role. Avoid deeply nested hierarchies; most organisations need 3-4 levels. The display name can differ from the ID, but keeping them consistent reduces confusion during policy assignments.', learnUrl: 'https://learn.microsoft.com/azure/governance/management-groups/overview' },
    { category: 'General', name: 'Subscription', provider: 'Microsoft.Subscription/subscriptions', abbrev: 'sub', maxLength: 64, scope: 'Tenant', chars: 'a-z, A-Z, 0-9, -, .', desc: 'Billing boundary and trust container for Azure resources with separate usage limits and quotas. Provides isolation for workloads with independent access control and cost tracking.', longDesc: 'Billing boundary and trust container for Azure resources with separate usage limits, quotas, and cost tracking. Subscriptions provide workload isolation at the billing level — each subscription has its own resource limits (e.g. 250 storage accounts, 50 Key Vaults per region) and generates a separate invoice. In the CAF model, subscriptions are placed within management groups to inherit governance policies. Enterprise customers typically use separate subscriptions per environment (prod/dev/staging) and per workload to isolate blast radius and simplify cost attribution. Azure Reservations and Savings Plans can be scoped to individual subscriptions or shared across a billing account.', bestPractice: 'Name pattern: sub-{purpose}-{env}. Include workload purpose and environment tier (prod/dev) for clear billing attribution.', namingGuidance: 'Name pattern: sub-{purpose}-{env}. Subscription names should clearly communicate the workload purpose and environment tier for easy identification in billing reports and the portal. Use names like sub-connectivity-prod or sub-payments-dev. Region is typically omitted since subscriptions are global. The CAF recommends dedicated subscriptions for platform services (connectivity, identity, management) and separate subscriptions per landing zone workload.', learnUrl: 'https://learn.microsoft.com/azure/azure-resource-manager/management/overview' },
    { category: 'General', name: 'Policy definition', provider: 'Microsoft.Authorization/policyDefinitions', abbrev: 'policy', maxLength: 64, scope: 'Scope', chars: 'a-z, A-Z, 0-9, -, _', desc: 'JSON-based rule enforcing compliance standards with effects like Deny, Audit, Modify, or DeployIfNotExists. Evaluates resource properties at creation and during periodic compliance scans.', longDesc: 'JSON-based rule that enforces compliance standards across Azure resources with effects including Deny (block non-compliant creation), Audit (flag without blocking), Modify (auto-remediate tags and properties), and DeployIfNotExists (deploy dependent resources like diagnostic settings). Policies evaluate resource properties at creation time and during periodic compliance scans every 24 hours. Custom policies can target any ARM resource property, while built-in policies cover common scenarios like allowed locations, required tags, and allowed VM SKUs. Group related policies into Initiatives (policy sets) for simplified assignment and compliance tracking.', bestPractice: 'Name pattern: policy-{area}-{action}. Use descriptive names like policy-naming-audit or policy-security-deny-public-ip.', namingGuidance: 'Name pattern: policy-{area}-{action}. Include the compliance area (naming, security, networking, tagging) and the effect (audit, deny, deploy) for at-a-glance understanding. Custom policy names are limited to 64 characters, so use concise abbreviations. Group related policies into initiatives and name those similarly: init-security-baseline, init-caf-naming. Store custom policy definitions as code in a Git repository for version control and CI/CD deployment.', learnUrl: 'https://learn.microsoft.com/azure/governance/policy/overview' },
    { category: 'General', name: 'Policy assignment', provider: 'Microsoft.Authorization/policyAssignments', abbrev: 'pa', maxLength: 24, scope: 'Scope', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Binds a policy definition or initiative to a management group, subscription, or resource group scope. Supports parameter overrides and exclusions for flexible enforcement.', longDesc: 'Binds a policy definition or initiative to a specific scope — management group, subscription, or resource group — activating enforcement at that level and all child scopes. Supports parameter overrides to customise policy behaviour per assignment (e.g. different allowed locations per subscription) and resource exclusions for known exceptions. Each assignment can use a managed identity for remediation tasks when using Modify or DeployIfNotExists effects. Non-compliance data flows to the Azure Policy compliance dashboard, providing a centralised view of organisational posture across all assignments and scopes.', bestPractice: 'Name pattern: pa-{policy}-{scope}. Keep under 24 chars; use abbreviations for policy name and target scope.', namingGuidance: 'Name pattern: pa-{policy}-{scope}. The 24-character limit is very restrictive — use short abbreviations for both the policy name and target scope. For example, pa-naming-aud-prod or pa-loc-deny-mg1. The display name (up to 128 chars) can be more descriptive and is what appears in the compliance dashboard, so rely on it for human readability while keeping the resource name compact.', learnUrl: 'https://learn.microsoft.com/azure/governance/policy/overview' },

    // Compute
    {
        category: 'Compute', name: 'Virtual Machine - Windows', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-machines', provider: 'Microsoft.Compute/virtualMachines', abbrev: 'vmw', maxLength: 15, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'IaaS compute running Windows Server. Hostname limited to 15 characters due to NetBIOS constraints. Supports Azure Hybrid Benefit (up to 40% savings) and Trusted Launch for protection against boot kits.', longDesc: 'IaaS compute running Windows Server with full OS-level control. The hostname is limited to 15 characters due to legacy NetBIOS naming constraints, which also sets the computer name in Active Directory. Azure Hybrid Benefit can reduce compute costs by up to 40% for existing Windows Server licences. Trusted Launch provides Secure Boot and vTPM to protect against boot kits and rootkits. Consider pairing with Azure Backup for automated recovery points and Azure Monitor Agent for performance and diagnostics.', bestPractice: 'Name pattern: vmw-{workload}-{env}-{###}. Keep short to fit 15-char limit.', namingGuidance: 'Name pattern: vmw-{workload}-{env}-{###}. The 15-character limit is strict — the VM name also becomes the Windows hostname, which must comply with NetBIOS constraints. Use short abbreviations for workload and environment, and append a numeric suffix for scaling (e.g. vmw-pay-prod-01). Avoid region in the name due to the length constraint; document it via tags instead.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/windows/naming-conventions'
    },
    {
        category: 'Compute', name: 'Virtual Machine - Linux', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-machines', provider: 'Microsoft.Compute/virtualMachines', abbrev: 'vml', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, .', desc: 'IaaS compute running Linux distributions (Ubuntu, RHEL, SUSE). Supports longer hostnames (up to 64 chars) and periods in name. Choose from General Purpose (D-series), Compute Optimized (F-series), or Memory Optimized (E-series) sizes.', longDesc: 'IaaS compute running Linux distributions including Ubuntu, RHEL, SUSE, and Flatcar. Unlike Windows VMs, Linux supports longer hostnames (up to 64 characters) and periods in the name. VM sizes span General Purpose (D-series), Compute Optimized (F-series), Memory Optimized (E-series), and GPU-accelerated (N-series) families. Supports cloud-init for declarative provisioning, Azure AD SSH login, and accelerated networking for up to 40 Gbps throughput. Use Spot VMs for interruptible workloads at up to 90% savings.', bestPractice: 'Name pattern: vml-{workload}-{env}-{region}-{###}. Standard naming pattern applies.', namingGuidance: 'Name pattern: vml-{workload}-{env}-{region}-{###}. The full naming pattern can be used since Linux supports up to 64 characters. Include region for multi-region deployments and a numeric suffix for scaling within a tier. Use lowercase for consistency with Linux hostname conventions. For ephemeral workloads consider omitting the numeric suffix.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/linux/naming-conventions'
    },
    { category: 'Compute', name: 'VM scale set', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-machine-scale-sets', provider: 'Microsoft.Compute/virtualMachineScaleSets', abbrev: 'vmss', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Autoscaling group of identical VMs with automatic load balancing and zone-redundant deployment. Supports up to 1,000 instances with Flexible or Uniform orchestration modes.', longDesc: 'Autoscaling group of identical VMs that automatically adjusts instance count based on demand or schedule. Supports up to 1,000 instances per scale set with automatic load balancing across zones. Flexible orchestration mode (recommended for new deployments) allows mixing VM sizes and adding existing VMs, while Uniform mode enforces identical instances. Scale sets integrate with Azure Load Balancer and Application Gateway for traffic distribution, and support rolling upgrades with automatic OS image updates. Use with availability zones for 99.99% SLA.', bestPractice: 'Name pattern: vmss-{workload}-{env}-{region}. Instance names auto-generated; include workload tier (web/api/worker).', namingGuidance: 'Name pattern: vmss-{workload}-{env}-{region}. Individual VM instances within the scale set are auto-named with a numeric suffix, so focus the scale set name on identifying the workload tier it serves (e.g. vmss-frontend-prod-uks, vmss-worker-dev-weu). Use Flexible orchestration mode for new deployments to allow heterogeneous VM sizes and manual instance additions.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machine-scale-sets/overview' },
    { category: 'Compute', name: 'Availability set', provider: 'Microsoft.Compute/availabilitySets', abbrev: 'avail', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Logical grouping distributing VMs across fault domains (rack-level isolation) and update domains (rolling updates). Provides 99.95% SLA within a single datacenter.', longDesc: 'Logical grouping that distributes VMs across fault domains (separate physical racks with independent power and networking) and update domains (groups updated sequentially during platform maintenance). Provides a 99.95% SLA by ensuring at least one VM remains available during planned or unplanned downtime. Availability sets support up to 3 fault domains and 20 update domains. VMs must be added to the set at creation time and cannot be moved after deployment. This is a legacy availability model — Availability Zones provide stronger protection by distributing across physically separate datacenters within a region.', bestPractice: 'Name pattern: avail-{workload}-{tier}. Legacy availability model; use Availability Zones for new deployments where possible to achieve zone redundancy.', namingGuidance: 'Name pattern: avail-{workload}-{tier}. Include the workload and application tier (web, api, db) to clearly identify which VMs belong to each set. Availability sets are a legacy model — for new deployments, prefer Availability Zones which provide a 99.99% SLA with cross-datacenter redundancy. If you must use availability sets, create one per application tier and align fault domain count with your redundancy requirements.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/availability-set-overview' },
    {
        category: 'Compute', name: 'Managed disk', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=managed-disks', provider: 'Microsoft.Compute/disks', abbrev: 'disk', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Block storage with automatic replication (LRS/ZRS), incremental snapshots, and performance tiers from Standard HDD to Ultra Disk (160K IOPS). Supports server-side encryption with platform or customer-managed keys.', longDesc: 'Block storage volumes managed by Azure with automatic replication (LRS for local redundancy, ZRS for zone redundancy) and incremental snapshots for efficient backup. Performance tiers range from Standard HDD (low-cost archive) through Standard SSD and Premium SSD to Ultra Disk (up to 160,000 IOPS and 4,000 MB/s throughput). All managed disks are encrypted at rest by default with platform-managed keys; customer-managed keys (CMK) via Key Vault and Disk Encryption Sets provide additional control. Shared disks support multi-attach for Windows Server Failover Clusters and Linux Pacemaker clusters.', bestPractice: 'Name pattern: disk-{vmname}-{type##}. Include parent VM name and disk type (os/data01) for easy identification.', namingGuidance: 'Name pattern: disk-{vmname}-{type##}. Always include the parent VM name to create a clear relationship between the disk and its VM (e.g. disk-vmw-pay-prod-01-os, disk-vmw-pay-prod-01-data01). Use the type suffix to distinguish between OS and data disks, and append a numeric index when a VM has multiple data disks. This convention makes it easy to identify orphaned disks after VM deletion.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/managed-disks-overview', subResources: [
            { suffix: 'os', label: 'OS Disk', dnsZone: null },
            { suffix: 'data', label: 'Data Disk', dnsZone: null },
            { suffix: 'temp', label: 'Temp Disk', dnsZone: null }
        ]
    },
    { category: 'Compute', name: 'Disk encryption set', provider: 'Microsoft.Compute/diskEncryptionSets', abbrev: 'des', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Enables customer-managed keys (CMK) stored in Key Vault for encrypting managed disks. Supports automatic key rotation and double encryption with platform and customer keys.', longDesc: 'Enables customer-managed keys (CMK) stored in Azure Key Vault for encrypting managed disks, providing full control over the encryption key lifecycle. Supports automatic key rotation — when a new key version is created in Key Vault, Azure automatically re-wraps the disk encryption key within 1 hour. Double encryption combines platform-managed and customer-managed keys for two layers of protection, meeting stringent compliance requirements. A single disk encryption set can be referenced by multiple managed disks, ensuring consistent encryption policy across a workload. Requires Key Vault with soft-delete and purge protection enabled.', bestPractice: 'Name pattern: des-{workload}-{env}. One per workload/env; reference in disk deployments for consistent encryption.', namingGuidance: 'Name pattern: des-{workload}-{env}. Create one disk encryption set per workload and environment to isolate encryption keys and simplify key rotation. Reference the same DES across all managed disks within a workload for consistency. The DES must be in the same region as the disks it encrypts, so include the region in the name for multi-region deployments (e.g. des-payments-prod-uks).', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/disk-encryption' },
    { category: 'Compute', name: 'Image', provider: 'Microsoft.Compute/images', abbrev: 'img', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Generalized or specialized VM capture containing OS disk and data disk configurations. Supports creation from running VMs, VHD files, or managed snapshots.', longDesc: 'Generalized or specialized VM capture containing OS disk and optional data disk configurations. Generalized images have been sysprep\'d (Windows) or deprovisioned (Linux) and can be used to create new VMs with unique identities, while specialized images retain the original VM\'s identity, hostname, and configuration. Images can be created from running VMs, uploaded VHD files, or existing managed snapshots. For enterprise-scale golden image distribution, use Azure Compute Gallery which adds versioning, replication, and RBAC-based sharing across tenants and regions.', bestPractice: 'Name pattern: img-{os}-{app}-{version}. Include OS type, application stack, and version number for image lineage tracking.', namingGuidance: 'Name pattern: img-{os}-{app}-{version}. Include the OS type (win2022, ubuntu2204), application stack, and a version number to track image lineage (e.g. img-win2022-iis-v3.1). For organisations with many images, use Azure Compute Gallery instead of standalone images — galleries provide built-in versioning, regional replication, and RBAC sharing.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/capture-image-portal' },
    { category: 'Compute', name: 'Compute gallery', provider: 'Microsoft.Compute/galleries', abbrev: 'gal', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, .', desc: 'Centralized repository for VM images with versioning, regional replication, and RBAC-based sharing across tenants. Supports both VM images and direct-share community galleries.', longDesc: 'Centralised repository for managing, versioning, and distributing VM images, application definitions, and OS disk snapshots at scale. Supports regional replication — image versions are automatically copied to target regions, enabling low-latency VM deployments globally. RBAC-based sharing allows controlled access across teams, subscriptions, and even tenants without copying images. Community galleries enable public sharing without requiring Azure Marketplace publishing. Each gallery contains image definitions (metadata like OS type, publisher, offer) and image versions (the actual bits), providing a structured hierarchy for golden image management.', bestPractice: 'Name pattern: gal{workload}{env}{region}{instance}. No hyphens allowed; use for golden image distribution.', namingGuidance: 'Name pattern: gal{workload}{env}{region}{instance}. Compute gallery names cannot contain hyphens — only alphanumeric characters and periods are allowed (e.g. galsharedproduks001). While the gallery typically serves an entire organisation, the Cloud Adoption Framework recommends applying the standard 5-part naming convention where possible. Image definitions within the gallery provide the more specific naming (e.g. windows-iis-base, ubuntu-docker-host).', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/azure-compute-gallery' },
    { category: 'Compute', name: 'Proximity placement group', provider: 'Microsoft.Compute/proximityPlacementGroups', abbrev: 'ppg', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Physical co-location constraint ensuring VMs deploy within the same Azure datacenter for sub-millisecond network latency. Required for latency-sensitive HPC and SAP HANA workloads.', longDesc: 'Physical co-location constraint that ensures VMs are deployed within the same Azure datacenter for the lowest possible network latency. When VMs are placed in a proximity placement group, Azure selects a datacenter stamp on first deployment and pins all subsequent VMs to that same physical location. This is critical for latency-sensitive workloads like HPC clusters, SAP HANA scale-out, and real-time financial trading systems where sub-millisecond inter-node communication is required. The trade-off is reduced availability — all resources share the same physical failure domain, so pair with availability zones where possible.', bestPractice: 'Name pattern: ppg-{workload}-{tier}. Create per application tier requiring low latency; reference in VM deployments.', namingGuidance: 'Name pattern: ppg-{workload}-{tier}. Create one PPG per application tier that requires low inter-node latency (e.g. ppg-sap-db, ppg-hpc-compute). Reference the PPG in VM and VMSS deployments to ensure co-location. Be aware that PPGs can limit availability — only use them when sub-millisecond latency is a genuine requirement, not as a default.', learnUrl: 'https://learn.microsoft.com/azure/virtual-machines/co-location' },
    { category: 'Compute', name: 'Function app', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=functions', provider: 'Microsoft.Web/sites', abbrev: 'func', maxLength: 60, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Serverless compute executing event-driven code with automatic scaling from zero to thousands of instances. Supports C#, JavaScript, Python, Java, and PowerShell with triggers for HTTP, queues, timers, and more.', longDesc: 'Serverless compute executing event-driven code with automatic scaling from zero to thousands of instances. Supports C#, JavaScript, Python, Java, and PowerShell with triggers for HTTP, queues, timers, Event Grid, Cosmos DB change feed, and more. The Consumption plan charges per execution and offers zero-cost idle time, while the Premium plan adds VNet integration, unlimited duration, and pre-warmed instances to avoid cold starts. Use Durable Functions for stateful orchestration patterns like fan-out/fan-in and human interaction workflows.', bestPractice: 'Name pattern: func-{workload}-{purpose}-{env}. Globally unique; include purpose (api/processor/scheduler) for clarity.', namingGuidance: 'Name pattern: func-{workload}-{purpose}-{env}. The name must be globally unique as it forms the default hostname {name}.azurewebsites.net. Include a purpose suffix (api, processor, scheduler, webhook) to distinguish multiple function apps within the same workload. For microservice architectures, align names with the bounded context they serve.', learnUrl: 'https://learn.microsoft.com/azure/azure-functions/functions-overview' },
    { category: 'Compute', name: 'Batch account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=batch', provider: 'Microsoft.Batch/batchAccounts', abbrev: 'ba', maxLength: 24, scope: 'Region', chars: 'a-z, 0-9', desc: 'Managed service for running large-scale parallel and HPC batch jobs across pools of VMs. Features automatic scaling, job scheduling, and integration with low-priority/Spot VMs for cost optimization.', longDesc: 'Managed service for running large-scale parallel and high-performance computing (HPC) batch jobs across pools of Azure VMs. Batch handles VM provisioning, task scheduling, auto-scaling, and failure recovery automatically. Compute pools can use dedicated VMs, low-priority VMs (up to 80% savings), or Spot VMs for interruptible workloads. Supports both cloud-native tasks (containers, command lines) and multi-instance MPI jobs for tightly coupled HPC workloads. Integrates with Azure Storage for input/output data staging and supports custom VM images for pre-configured environments.', bestPractice: 'Name pattern: ba{workload}{env}. Max 24 chars lowercase only; no hyphens allowed in Batch account names.', namingGuidance: 'Name pattern: ba{workload}{env}. Batch account names are limited to 24 lowercase characters with no hyphens or special characters. Use short workload and environment abbreviations concatenated together (e.g. barenderingprod, bagenomicsdev). The account is regional, so include a region abbreviation only if you deploy multiple Batch accounts across regions.', learnUrl: 'https://learn.microsoft.com/azure/batch/batch-technical-overview' },
    { category: 'Compute', name: 'Azure Spring Apps', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=spring-apps', provider: 'Microsoft.AppPlatform/Spring', abbrev: 'spring', maxLength: 32, scope: 'Resource group', chars: 'a-z, 0-9, -', desc: 'Fully managed service for Spring Boot apps with built-in service discovery, configuration management, and distributed tracing. Supports blue-green deployments and auto-scaling.', longDesc: 'Fully managed platform for Spring Boot and Spring Cloud applications with built-in Eureka service discovery, Spring Cloud Config for externalized configuration, and Zipkin-based distributed tracing. Supports blue-green deployments via staging environments, auto-scaling based on metrics, and native integration with Azure Monitor for observability. Enterprise tier adds VMware Tanzu components including API Portal, Application Configuration Service, and Spring Cloud Gateway for advanced microservice patterns. VNet injection provides network isolation for enterprise workloads.', bestPractice: 'Name pattern: spring-{workload}-{env}. Globally unique; use for microservices architecture.', namingGuidance: 'Name pattern: spring-{workload}-{env}. The name is limited to 32 characters and must be globally unique. Use short abbreviations for the workload and environment (e.g. spring-orders-prod, spring-catalog-dev). The name forms part of the service endpoint URL. For enterprise-scale Spring microservices, use a single Spring Apps instance per environment with individual apps deployed within it.', learnUrl: 'https://learn.microsoft.com/azure/spring-apps/overview' },

    // Networking
    { category: 'Networking', name: 'Virtual network', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-network', provider: 'Microsoft.Network/virtualNetworks', abbrev: 'vnet', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Software-defined network providing isolation, segmentation, and connectivity. Critical for security boundaries; supports VNet Peering for hub-and-spoke topologies and Service Endpoints/Private Links for PaaS security.', longDesc: 'Software-defined network providing isolation, segmentation, and connectivity for Azure resources. Virtual networks are the foundation of Azure networking — they define address spaces, host subnets, and enforce security boundaries via NSGs and route tables. VNet Peering enables low-latency, high-bandwidth connectivity across VNets (including cross-region), while Service Endpoints and Private Links secure traffic to PaaS services. In a hub-and-spoke topology, the hub VNet centralises shared services (firewall, VPN gateway, DNS) with spoke VNets peered for workload isolation.', bestPractice: 'Name pattern: vnet-{workload|hub|spoke}-{env}-{region}. Use hub/spoke designation for network topology clarity.', namingGuidance: 'Name pattern: vnet-{workload|hub|spoke}-{env}-{region}. Always include the topology role (hub, spoke, or workload name) as it is critical for operational clarity when managing peering relationships. Include the region since VNets are regional resources and cross-region peering uses different names. In CAF landing zones, use vnet-hub-{env}-{region} for the central hub and vnet-spoke-{workload}-{env}-{region} for workload spokes.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/virtual-networks-overview' },
    {
        category: 'Networking', name: 'Subnet', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-network', provider: 'Microsoft.Network/virtualNetworks/subnets', abbrev: 'snet', maxLength: 80, scope: 'VNet', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'IP address range segment within a VNet for organizing resources and applying network policies. Supports delegation to Azure services, NSG association, and route table binding.', longDesc: 'IP address range segment within a virtual network for organising resources and applying network security policies. Each subnet hosts Azure resources and can be associated with a Network Security Group (NSG) for traffic filtering, a Route Table for custom routing, and a NAT Gateway for outbound internet access. Service delegation locks a subnet to a specific Azure service (e.g. Azure SQL Managed Instance, App Service) which then manages internal resources. Some Azure services require dedicated subnets with mandatory names (AzureFirewallSubnet, AzureBastionSubnet, GatewaySubnet). Subnet address ranges cannot overlap with other subnets in the same VNet.', bestPractice: 'Name pattern: snet-{vnetname}-{purpose}. Include parent VNet name; use purpose suffix to identify workload tier or Azure service delegation.', namingGuidance: 'Name pattern: snet-{vnetname}-{purpose}. Include the parent VNet name for context when viewing subnets across multiple networks. Use the purpose suffix to identify the workload tier (web, app, db) or Azure service (aks, pe, agw). Some subnets have mandatory names imposed by Azure: AzureFirewallSubnet, AzureBastionSubnet, GatewaySubnet, AzureFirewallManagementSubnet, and RouteServerSubnet. These cannot be renamed and must be used exactly as specified.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/virtual-network-manage-subnet', subResources: [
            { suffix: 'web', label: 'Web Tier', dnsZone: null },
            { suffix: 'app', label: 'Application Tier', dnsZone: null },
            { suffix: 'db', label: 'Database Tier', dnsZone: null },
            { suffix: 'agw', label: 'Application Gateway', dnsZone: null },
            { suffix: 'afw', label: 'Azure Firewall', dnsZone: null },
            { suffix: 'bas', label: 'Bastion Host', dnsZone: null },
            { suffix: 'aks', label: 'AKS Cluster', dnsZone: null },
            { suffix: 'pe', label: 'Private Endpoints', dnsZone: null },
            { suffix: 'gw', label: 'Virtual Network Gateway', dnsZone: null },
            { suffix: 'afwm', label: 'Azure Firewall Management', dnsZone: null },
            { suffix: 'rs', label: 'Route Server', dnsZone: null }
        ]
    },
    { category: 'Networking', name: 'Network security group', provider: 'Microsoft.Network/networkSecurityGroups', abbrev: 'nsg', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Stateful packet filter with priority-based allow/deny rules for TCP, UDP, and ICMP traffic. Supports service tags, ASGs, and augmented rules for simplified management at scale.', longDesc: 'Stateful packet filter with priority-based allow/deny rules for TCP, UDP, and ICMP traffic. NSGs operate at both the subnet and NIC level, with subnet association being the recommended approach for consistent enforcement. Service tags (e.g. AzureLoadBalancer, Internet, VirtualNetwork) simplify rule management for Azure services, while Application Security Groups (ASGs) allow application-centric rules without explicit IP addresses. Enable NSG flow logs via Network Watcher for traffic visibility, threat detection, and compliance auditing.', bestPractice: 'Name pattern: nsg-{subnet|vm}-{purpose}. Associate with subnet names; one NSG per subnet is preferred pattern.', namingGuidance: 'Name pattern: nsg-{subnet|vm}-{purpose}. The CAF best practice is one NSG per subnet, named to match the subnet it protects (e.g. nsg-snet-web, nsg-snet-db). This creates an intuitive mapping between network segments and their security policies. Avoid creating overly permissive shared NSGs — each subnet should have tailored rules. Enable flow logs to a storage account for audit and traffic analysis.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/network-security-groups-overview' },
    { category: 'Networking', name: 'Application security group', provider: 'Microsoft.Network/applicationSecurityGroups', abbrev: 'asg', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Logical grouping of VM NICs enabling application-centric NSG rules without explicit IP management. Simplifies rule maintenance as workloads scale and IP addresses change.', longDesc: 'Logical grouping of VM network interfaces that enables application-centric NSG rules without managing explicit IP addresses. When VMs are added to or removed from an ASG, the associated NSG rules automatically apply to the new configuration — no manual IP updates required. ASGs eliminate the need for IP-based rules that break when VMs are scaled, redeployed, or migrated. They work as source and destination in NSG rules, enabling intuitive rules like "allow traffic from asg-web to asg-db on port 1433". ASGs must be in the same region as the NICs they group.', bestPractice: 'Name pattern: asg-{workload}-{role}. Group by application role (web/api/db) for simplified NSG rule management.', namingGuidance: 'Name pattern: asg-{workload}-{role}. Create one ASG per application role (e.g. asg-payments-web, asg-payments-api, asg-payments-db) to enable intuitive, application-centric NSG rules. This approach decouples security rules from specific IP addresses, making rules resilient to VM scaling and redeployment. All ASGs referenced in a single NSG rule must be in the same region.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/application-security-groups' },
    {
        category: 'Networking', name: 'Public IP', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=ip-addresses', provider: 'Microsoft.Network/publicIPAddresses', abbrev: 'pip', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Internet-routable IPv4/IPv6 address for VMs, load balancers, and gateways. Standard SKU provides static IPs, zone-redundancy, and DDoS protection integration.', longDesc: 'Internet-routable IPv4 or IPv6 address resource for VMs, load balancers, application gateways, VPN gateways, and other Azure services requiring public connectivity. Standard SKU (recommended) provides static allocation, zone-redundant deployment across availability zones, and integration with Azure DDoS Protection. Public IPs can have DNS labels that create an FQDN ({label}.{region}.cloudapp.azure.com). Basic SKU is being retired — all new deployments should use Standard SKU. Idle timeout is configurable from 4-30 minutes for TCP connections.', bestPractice: 'Name pattern: pip-{resource}-{env}-{region}. Include associated resource type suffix and resource name for quick correlation in portal.', namingGuidance: 'Name pattern: pip-{resource}-{env}-{region}. Include the associated resource type and purpose to quickly identify what each public IP is attached to (e.g. pip-afw-hub-prod-uks, pip-agw-web-prod-uks, pip-vpng-hub-prod-uks). This makes it easy to spot orphaned IPs after resource deletion. Use Standard SKU for all new deployments as Basic is being retired.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/ip-services/public-ip-addresses', subResources: [
            { suffix: 'vm', label: 'Virtual Machine', dnsZone: null },
            { suffix: 'afw', label: 'Azure Firewall', dnsZone: null },
            { suffix: 'agw', label: 'Application Gateway', dnsZone: null },
            { suffix: 'vpng', label: 'VPN Gateway', dnsZone: null },
            { suffix: 'bas', label: 'Bastion Host', dnsZone: null },
            { suffix: 'ngw', label: 'NAT Gateway', dnsZone: null },
            { suffix: 'lbe', label: 'External Load Balancer', dnsZone: null }
        ]
    },
    {
        category: 'Networking', name: 'Public IP prefix', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=ip-addresses', provider: 'Microsoft.Network/publicIPPrefixes', abbrev: 'ippre', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Reserves a contiguous CIDR block of public IPv4 addresses (/28 to /31) for predictable outbound addressing. Ideal for NAT Gateway and firewall allowlisting scenarios.', longDesc: 'Reserves a contiguous CIDR block of public IPv4 addresses (from /31 with 2 IPs to /28 with 16 IPs) for predictable outbound addressing. Public IP prefixes guarantee that all IPs in the range are contiguous and from the same region, making them ideal for NAT Gateway (predictable outbound IPs), firewall allowlisting by external partners, and Azure Firewall SNAT. Individual public IPs can be carved from the prefix on demand. This eliminates the unpredictability of standard public IP allocation and simplifies firewall rule management for partners who need to allowlist your outbound addresses.', bestPractice: 'Name pattern: ippre-{resource}-{env}-{region}. Include the associated resource type suffix to identify what the prefix supports.', namingGuidance: 'Name pattern: ippre-{resource}-{env}-{region}. Include the target resource type suffix to clearly identify what the prefix is allocated to (e.g. ippre-ngw-prod-uks for a NAT Gateway prefix, ippre-afw-hub-prod-uks for Azure Firewall). Document the actual CIDR range in resource tags since this cannot be determined from the name. The prefix size is chosen at creation and cannot be changed afterwards, so plan capacity carefully.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/ip-services/public-ip-address-prefix', subResources: [
            { suffix: 'ngw', label: 'NAT Gateway', dnsZone: null },
            { suffix: 'afw', label: 'Azure Firewall', dnsZone: null },
            { suffix: 'lbe', label: 'External Load Balancer', dnsZone: null },
            { suffix: 'vpng', label: 'VPN Gateway', dnsZone: null }
        ]
    },
    {
        category: 'Networking', name: 'Load balancer', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=load-balancer', provider: 'Microsoft.Network/loadBalancers', abbrev: 'lb', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Layer 4 TCP/UDP load balancer with sub-millisecond latency. Standard SKU supports zone-redundancy and high availability for both internal and external scenarios.', longDesc: 'Layer 4 (TCP/UDP) load balancer operating at the transport layer with sub-millisecond latency and millions of flows per second. Standard SKU (recommended) provides zone-redundant deployment, cross-zone load balancing, and HA ports for NVA scenarios. Internal load balancers distribute traffic within a VNet (e.g. between web and app tiers), while external load balancers handle internet-facing traffic. Health probes monitor backend pool members and automatically remove unhealthy instances from rotation. Outbound rules provide explicit control over SNAT for internet-bound traffic from backend pool members.', bestPractice: 'Name pattern: lb-{type}-{workload}-{env}. Include type suffix (i/e) for internal/external; external LBs need region in multi-region deployments.', namingGuidance: 'Name pattern: lb-{type}-{workload}-{env}. Always include the type suffix (i for internal, e for external) as this is the most critical operational distinction. For example, lb-i-api-prod for an internal API load balancer or lb-e-web-prod-uks for an external web load balancer. Use Standard SKU for all new deployments as Basic SKU is being retired.', learnUrl: 'https://learn.microsoft.com/azure/load-balancer/load-balancer-overview', subResources: [
            { suffix: 'i', label: 'Internal (Private)', dnsZone: null },
            { suffix: 'e', label: 'External (Public)', dnsZone: null }
        ]
    },
    { category: 'Networking', name: 'Application Gateway', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=application-gateway', provider: 'Microsoft.Network/applicationGateways', abbrev: 'agw', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Layer 7 load balancer with SSL/TLS termination, cookie-based session affinity, URL path routing, and multi-site hosting. Includes WebSocket support and native WAF integration.', longDesc: 'Layer 7 (HTTP/HTTPS) load balancer providing application-level traffic management with SSL/TLS termination, cookie-based session affinity, URL path-based routing, and multi-site hosting on a single gateway. Supports WebSocket and HTTP/2 protocols natively. Application Gateway v2 adds autoscaling (0-125 instances), zone redundancy, static VIP, and Key Vault certificate integration. The integrated Web Application Firewall (WAF) provides OWASP Core Rule Set protection against common web attacks like SQL injection and XSS. Requires a dedicated subnet (/24 recommended) for deployment.', bestPractice: 'Name pattern: agw-{workload}-{env}-{region}. Deploy in dedicated subnet; pair with WAF policy for web protection.', namingGuidance: 'Name pattern: agw-{workload}-{env}-{region}. Deploy in a dedicated subnet (typically /24) named snet-agw. Include the region since Application Gateway is a regional resource. Pair with a WAF policy for production web workloads. For multi-site hosting, the gateway name should reflect its broader purpose rather than individual sites.', learnUrl: 'https://learn.microsoft.com/azure/application-gateway/overview' },
    { category: 'Networking', name: 'Azure Firewall', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=azure-firewall', provider: 'Microsoft.Network/azureFirewalls', abbrev: 'afw', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Cloud-native stateful firewall-as-a-service with built-in high availability and Microsoft threat intelligence. Supports FQDN filtering, network/application rules, IDPS, and TLS inspection.', longDesc: 'Cloud-native stateful firewall-as-a-service with built-in high availability, unrestricted scalability, and Microsoft Threat Intelligence-based filtering. Supports FQDN-based outbound filtering, network rules, application rules with URL filtering, Intrusion Detection and Prevention System (IDPS) with signature-based detection, and TLS inspection for encrypted traffic. Premium SKU adds IDPS, TLS inspection, URL filtering, and web categories. Azure Firewall is the cornerstone of the hub-spoke network topology, centralising traffic inspection and control for all spoke VNets. Requires the AzureFirewallSubnet (minimum /26).', bestPractice: 'Name pattern: afw-{hub}-{region}. Deploy in hub VNet; typically one per region in hub-spoke topology.', namingGuidance: 'Name pattern: afw-{hub}-{region}. In a hub-spoke topology, deploy one firewall per hub per region (e.g. afw-hub-uks, afw-hub-weu). The firewall must be deployed in a subnet named exactly AzureFirewallSubnet. Use Azure Firewall Policy (afwp) to manage rules separately from the firewall resource, enabling policy inheritance and sharing across multiple firewalls.', learnUrl: 'https://learn.microsoft.com/azure/firewall/overview' },
    { category: 'Networking', name: 'Firewall policy', provider: 'Microsoft.Network/firewallPolicies', abbrev: 'afwp', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Hierarchical rule collection container for Azure Firewall supporting rule inheritance and centralized management. Enables consistent policy across multiple firewalls.', longDesc: 'Hierarchical rule collection container for Azure Firewall that separates rule management from the firewall resource itself. Supports parent-child policy inheritance — base policies define organisation-wide rules (e.g. deny all, allow Microsoft services) while child policies add workload-specific rules. A single policy can be shared across multiple firewalls for consistent enforcement. Rule collection groups contain network rules, application rules, and DNAT rules with priority-based processing. Policies support Threat Intelligence, IDPS signatures, and TLS inspection configuration independent of the firewall instance.', bestPractice: 'Name pattern: afwp-{scope}-{purpose}. Use base/child hierarchy like afwp-base, afwp-prod-web for inheritance.', namingGuidance: 'Name pattern: afwp-{scope}-{purpose}. Structure policy names to reflect the inheritance hierarchy — afwp-base for the root policy, afwp-prod for environment-level overrides, and afwp-prod-web for workload-specific rules. This naming convention mirrors the policy hierarchy and makes rule troubleshooting intuitive. Always use policies instead of classic rules for new Azure Firewall deployments.', learnUrl: 'https://learn.microsoft.com/azure/firewall-manager/policy-overview' },
    { category: 'Networking', name: 'VPN Gateway', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=vpn-gateway', provider: 'Microsoft.Network/virtualNetworkGateways', abbrev: 'vgw', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Encrypted tunnel gateway supporting IKEv2/OpenVPN for site-to-site, point-to-site, and VNet-to-VNet connectivity. Offers up to 10 Gbps throughput with BGP routing support.', longDesc: 'Encrypted tunnel gateway supporting IKEv2 and OpenVPN protocols for site-to-site (S2S), point-to-site (P2S), and VNet-to-VNet connectivity. S2S connections link on-premises networks to Azure over IPsec/IKE tunnels, P2S enables individual workstations to connect securely, and VNet-to-VNet provides encrypted cross-region connectivity. VpnGw2-VpnGw5 SKUs offer 1.25 to 10 Gbps aggregate throughput with BGP routing support for dynamic route exchange. Active-active configuration provides redundancy with two tunnel instances. Requires the GatewaySubnet (/27 or larger recommended).', bestPractice: 'Name pattern: vgw-{hub}-{region}. One per hub VNet in GatewaySubnet; use active-active for HA.', namingGuidance: 'Name pattern: vgw-{hub}-{region}. Deploy in the GatewaySubnet (mandatory name, /27 or larger recommended). In hub-spoke topologies, the VPN gateway resides in the hub VNet and provides connectivity for all peered spokes. Use active-active mode for production to maintain connectivity during platform maintenance. Name reflects the hub VNet and region (e.g. vgw-hub-uks).', learnUrl: 'https://learn.microsoft.com/azure/vpn-gateway/vpn-gateway-about-vpngateways' },
    { category: 'Networking', name: 'ExpressRoute circuit', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=expressroute', provider: 'Microsoft.Network/expressRouteCircuits', abbrev: 'erc', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Private Layer 2/3 connectivity from on-premises via a connectivity provider with up to 100 Gbps bandwidth. Enables Microsoft peering for O365/Dynamics and private peering for Azure VNets.', longDesc: 'Private Layer 2/3 connectivity from on-premises networks to Azure via a connectivity provider, bypassing the public internet for improved reliability, speed, and security. Bandwidth tiers range from 50 Mbps to 100 Gbps depending on the provider. Private peering connects to Azure VNets for IaaS/PaaS access, while Microsoft peering provides connectivity to Microsoft 365, Dynamics 365, and Azure PaaS with public endpoints. ExpressRoute Global Reach enables direct connectivity between on-premises sites through the Microsoft backbone. Premium add-on extends connectivity across geopolitical regions and increases route limits.', bestPractice: 'Name pattern: erc-{provider}-{location}-{bandwidth}. Include provider and bandwidth for capacity planning.', namingGuidance: 'Name pattern: erc-{provider}-{location}-{bandwidth}. Include the connectivity provider name, peering location, and bandwidth tier for capacity planning and operational clarity (e.g. erc-equinix-london-1gbps). For redundancy, deploy two circuits from different peering locations and reflect this in the naming. ExpressRoute circuits are long-lived infrastructure resources, so choose names that remain meaningful over time.', learnUrl: 'https://learn.microsoft.com/azure/expressroute/expressroute-introduction' },
    { category: 'Networking', name: 'Virtual WAN', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-wan', provider: 'Microsoft.Network/virtualWans', abbrev: 'vwan', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Microsoft-managed networking service providing any-to-any transit connectivity across branches, VNets, and users. Integrates SD-WAN, VPN, ExpressRoute, and point-to-site in a unified architecture.', longDesc: 'Microsoft-managed networking service providing any-to-any transit connectivity across branch offices, VNets, remote users, and cloud workloads in a unified hub architecture. Virtual WAN automates the complexity of hub-spoke networking by managing VNet peering, routing, VPN, and ExpressRoute connectivity. Supports integration with SD-WAN partners for automated branch deployment, built-in site-to-site VPN (up to 20 Gbps), point-to-site VPN for remote users, and ExpressRoute circuits. Routing is handled automatically between all connected entities. Secured Virtual Hubs add Azure Firewall integration for centralised traffic inspection.', bestPractice: 'Name pattern: vwan-{workload}-{env}-{region}-{instance}. Contains multiple regional hubs.', namingGuidance: 'Name pattern: vwan-{workload}-{env}-{region}-{instance}. Following the Cloud Adoption Framework, use the standard 5-part naming convention (e.g. vwan-corporate-prod-uks-001) for consistency. Although a Virtual WAN spans multiple regions through its hubs, it is still deployed into a specific region and resource group, so the primary region is included in the name. Regional hubs within the vWAN provide further per-region naming. The vWAN type (Basic or Standard) is chosen at creation.', learnUrl: 'https://learn.microsoft.com/azure/virtual-wan/virtual-wan-about' },
    { category: 'Networking', name: 'Virtual hub', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-wan', provider: 'Microsoft.Network/virtualHubs', abbrev: 'vhub', maxLength: 80, scope: 'vWAN', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Regional virtual WAN routing hub with automated VNet peering and inter-hub connectivity. Hosts VPN, ExpressRoute, and Azure Firewall deployments for centralized traffic management.', longDesc: 'Regional routing hub within a Virtual WAN that automates VNet peering, inter-hub mesh connectivity, and centralised traffic management. Each hub is deployed to a specific Azure region and automatically establishes full-mesh connectivity with other hubs in the vWAN. Connected spoke VNets gain transit connectivity to all other spokes and branches without manual route table management. Hubs can host VPN gateways, ExpressRoute gateways, and point-to-site gateways. Secured Virtual Hubs add Azure Firewall or third-party NVA for centralised security inspection of inter-spoke, internet, and branch traffic.', bestPractice: 'Name pattern: vhub-{region}. One per region within vWAN; auto-peers to connected spoke VNets.', namingGuidance: 'Name pattern: vhub-{region}. Since hubs are regional resources within a vWAN, the region is the primary identifier (e.g. vhub-uks, vhub-weu). One hub per region is the standard pattern. When using Secured Virtual Hubs with Azure Firewall, the hub name also appears in the firewall resource naming, so keep it concise and consistent.', learnUrl: 'https://learn.microsoft.com/azure/virtual-wan/virtual-wan-about' },
    { category: 'Networking', name: 'NAT Gateway', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=nat-gateway', provider: 'Microsoft.Network/natGateways', abbrev: 'ngw', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Fully managed outbound NAT service providing static public IP addresses and up to 50 Gbps throughput. Eliminates SNAT port exhaustion for VMs and scale sets.', longDesc: 'Fully managed outbound NAT service providing static, predictable public IP addresses for outbound internet connectivity with up to 50 Gbps throughput and 64,000 SNAT ports per public IP. NAT Gateway eliminates SNAT port exhaustion issues that commonly affect VMs and scale sets using default outbound access or load balancer SNAT. Associated at the subnet level, all resources in the subnet automatically use the NAT Gateway for outbound traffic. Supports up to 16 public IP addresses or public IP prefixes for high-throughput scenarios. On-demand connection handling with no idle timeouts on established flows.', bestPractice: 'Name pattern: ngw-{vnet|subnet}-{region}. Associate at subnet level; name reflects scope of NAT coverage.', namingGuidance: 'Name pattern: ngw-{vnet|subnet}-{region}. Associate at the subnet level and name to reflect the scope of NAT coverage (e.g. ngw-spoke-app-uks for an application subnet\'s NAT, or ngw-hub-shared-uks for shared services). A single NAT Gateway can be associated with multiple subnets in the same VNet. Use public IP prefixes for contiguous outbound IP ranges when partners need to allowlist your addresses.', learnUrl: 'https://learn.microsoft.com/azure/nat-gateway/nat-overview' },
    { category: 'Networking', name: 'Route table', provider: 'Microsoft.Network/routeTables', abbrev: 'rt', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'User-defined routes (UDRs) controlling traffic flow between subnets, to NVAs, or to the internet. Overrides Azure system routes with custom next-hop destinations.', longDesc: 'User-defined routes (UDRs) that control traffic flow between subnets, to network virtual appliances (NVAs), or to the internet, overriding Azure\'s default system routes. Critical for hub-spoke topologies where all traffic must flow through a central firewall — UDRs with next-hop of the firewall\'s private IP force traffic inspection. Route tables are associated at the subnet level, and a single table can be shared across multiple subnets with identical routing requirements. The "Propagate gateway routes" setting controls whether VPN/ExpressRoute learned routes are injected into the subnet. BGP route propagation can be disabled per route table.', bestPractice: 'Name pattern: rt-{subnet|purpose}. Create per subnet or shared across similar subnets; document UDR purpose.', namingGuidance: 'Name pattern: rt-{subnet|purpose}. Name route tables to match the subnets they are associated with (e.g. rt-snet-web, rt-snet-db) for clear mapping. In hub-spoke topologies, spoke subnets typically share a common route table that directs 0.0.0.0/0 to the hub firewall (e.g. rt-spoke-default). Document specific UDRs in tags or a CMDB since the route table name cannot convey all routing details.', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/virtual-networks-udr-overview' },
    {
        category: 'Networking', name: 'Private endpoint (Storage)', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=private-link', provider: 'Microsoft.Network/privateEndpoints', abbrev: 'pe', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Private connectivity to Azure Storage services enabling secure access from VNets without public internet exposure. Supports Blob, File, Table, Queue, and Data Lake sub-resources.', longDesc: 'Private connectivity to Azure Storage services through a network interface with a private IP address from your VNet, eliminating exposure to the public internet. Each private endpoint targets a specific storage sub-resource (blob, file, table, queue, dfs, web). Traffic flows over the Microsoft backbone network, never traversing the internet. Requires DNS configuration — either Azure Private DNS zones integrated with your VNet, or custom DNS entries — to resolve the storage account\'s FQDN to the private IP address. Multiple private endpoints can target different sub-resources of the same storage account.', bestPractice: 'Name pattern: pe-{storageaccount}-{service}. Include storage account name and target service. Register DNS in corresponding privatelink zone.', namingGuidance: 'Name pattern: pe-{storageaccount}-{service}. Always include both the target storage account name and the specific sub-resource type (blob, file, table, queue, dfs) to uniquely identify each endpoint (e.g. pe-stpayments-blob, pe-stpayments-file). Create the corresponding Private DNS zone (e.g. privatelink.blob.core.windows.net) and link it to your VNet for automatic name resolution.', learnUrl: 'https://learn.microsoft.com/azure/private-link/private-endpoint-overview', subResources: [
            { suffix: 'blob', label: 'Blob Storage', dnsZone: 'privatelink.blob.core.windows.net' },
            { suffix: 'file', label: 'File Storage', dnsZone: 'privatelink.file.core.windows.net' },
            { suffix: 'table', label: 'Table Storage', dnsZone: 'privatelink.table.core.windows.net' },
            { suffix: 'queue', label: 'Queue Storage', dnsZone: 'privatelink.queue.core.windows.net' },
            { suffix: 'dfs', label: 'Data Lake (DFS)', dnsZone: 'privatelink.dfs.core.windows.net' },
            { suffix: 'web', label: 'Static Website', dnsZone: 'privatelink.web.core.windows.net' }
        ]
    },
    {
        category: 'Networking', name: 'Private endpoint (Database)', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=private-link', provider: 'Microsoft.Network/privateEndpoints', abbrev: 'pe', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Private connectivity to Azure database services including SQL, Cosmos DB, MySQL, PostgreSQL, and Redis. Keeps database traffic on Azure backbone.', longDesc: 'Private connectivity to Azure database services through a private IP address in your VNet, ensuring database traffic remains on the Azure backbone and never traverses the public internet. Supports SQL Database, SQL Managed Instance, Cosmos DB (all APIs), MySQL Flexible Server, PostgreSQL Flexible Server, and Azure Cache for Redis. Each private endpoint targets a specific database sub-resource and requires a corresponding Private DNS zone for name resolution. This is the recommended approach for production database workloads, replacing older VNet service endpoints with improved security and simplified network configuration.', bestPractice: 'Name pattern: pe-{servername}-{service}. Include server/account name and target service type.', namingGuidance: 'Name pattern: pe-{servername}-{service}. Include the database server or account name and the sub-resource type (e.g. pe-sql-payments-sql, pe-cosmos-orders-sql). Create the matching Private DNS zone linked to your VNet. For Cosmos DB, the sub-resource type matches the API (documents for SQL, mongo for MongoDB). After configuring private endpoints, disable public network access on the database for complete isolation.', learnUrl: 'https://learn.microsoft.com/azure/private-link/private-endpoint-overview', subResources: [
            { suffix: 'sql', label: 'SQL Database', dnsZone: 'privatelink.database.windows.net' },
            { suffix: 'sqlmi', label: 'SQL Managed Instance', dnsZone: 'privatelink.{region}.database.windows.net' },
            { suffix: 'cosmos-sql', label: 'Cosmos DB (SQL)', dnsZone: 'privatelink.documents.azure.com' },
            { suffix: 'cosmos-mongo', label: 'Cosmos DB (MongoDB)', dnsZone: 'privatelink.mongo.cosmos.azure.com' },
            { suffix: 'mysql', label: 'MySQL Flexible', dnsZone: 'privatelink.mysql.database.azure.com' },
            { suffix: 'psql', label: 'PostgreSQL Flexible', dnsZone: 'privatelink.postgres.database.azure.com' },
            { suffix: 'redis', label: 'Redis Cache', dnsZone: 'privatelink.redis.cache.windows.net' }
        ]
    },
    {
        category: 'Networking', name: 'Private endpoint (Services)', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=private-link', provider: 'Microsoft.Network/privateEndpoints', abbrev: 'pe', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Private connectivity to Azure PaaS services including Key Vault, Container Registry, Event Hubs, Service Bus, and more.', longDesc: 'Private connectivity to Azure PaaS services through a private IP address in your VNet, providing secure access to Key Vault, Container Registry, Event Hubs, Service Bus, App Service, Azure AI Search, Azure AI services, and Machine Learning workspaces. Each service has a specific sub-resource type and corresponding Private DNS zone. Private endpoints are essential for zero-trust networking architectures where all PaaS services must be accessed exclusively through the private network. Supports approval workflows for cross-tenant connections and automatic or manual DNS registration.', bestPractice: 'Name pattern: pe-{resourcename}-{service}. Include target resource name and service type for clarity.', namingGuidance: 'Name pattern: pe-{resourcename}-{service}. Include both the target resource name and service type for clear identification (e.g. pe-kv-payments-vault, pe-cr-contoso-registry, pe-sb-orders-namespace). Deploy private endpoints in a dedicated subnet (snet-pe) for simplified NSG management. Create centralised Private DNS zones in the hub/connectivity subscription and link them to all spoke VNets.', learnUrl: 'https://learn.microsoft.com/azure/private-link/private-endpoint-overview', subResources: [
            { suffix: 'vault', label: 'Key Vault', dnsZone: 'privatelink.vaultcore.azure.net' },
            { suffix: 'registry', label: 'Container Registry', dnsZone: 'privatelink.azurecr.io' },
            { suffix: 'namespace', label: 'Event Hubs', dnsZone: 'privatelink.servicebus.windows.net' },
            { suffix: 'namespace', label: 'Service Bus', dnsZone: 'privatelink.servicebus.windows.net' },
            { suffix: 'sites', label: 'App Service', dnsZone: 'privatelink.azurewebsites.net' },
            { suffix: 'searchService', label: 'Azure AI Search', dnsZone: 'privatelink.search.windows.net' },
            { suffix: 'account', label: 'Azure AI services', dnsZone: 'privatelink.cognitiveservices.azure.com' },
            { suffix: 'amlworkspace', label: 'Machine Learning', dnsZone: 'privatelink.api.azureml.ms' }
        ]
    },
    { category: 'Networking', name: 'Private Link service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=private-link', provider: 'Microsoft.Network/privateLinkServices', abbrev: 'pls', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Enables consumers to access your service via private endpoint using NAT to your Standard Load Balancer. Supports connection approval workflow and alias-based access.', longDesc: 'Enables consumers (in any tenant or subscription) to access your service via a private endpoint, with traffic NAT\'d to your Standard Load Balancer backend pool. The consumer creates a private endpoint that connects to your Private Link service, establishing a private, cross-tenant connection without exposing your service to the internet. Supports manual and auto-approval workflows for connection requests, allowing you to control which consumers can access your service. An alias (GUID-based FQDN) provides a stable identifier for consumers to reference without revealing your subscription or resource details. Ideal for SaaS providers and shared services teams.', bestPractice: 'Name pattern: pls-{service}-{env}. Creates alias for consumer private endpoint connections; use for SaaS.', namingGuidance: 'Name pattern: pls-{service}-{env}. Name after the service being exposed (e.g. pls-payments-api-prod, pls-shared-sql-prod). The Private Link service creates an alias that consumers use to connect, so the name is primarily for your own operational visibility. Configure visibility and auto-approval settings to control which subscriptions can connect.', learnUrl: 'https://learn.microsoft.com/azure/private-link/private-link-service-overview' },

    { category: 'Networking', name: 'Traffic Manager', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=traffic-manager', provider: 'Microsoft.Network/trafficmanagerprofiles', abbrev: 'traf', maxLength: 63, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'DNS-based global traffic distributor with priority, weighted, performance, geographic, and subnet routing methods. Supports endpoint health monitoring with automatic failover.', longDesc: 'DNS-based global traffic distribution service that routes users to the optimal endpoint based on configurable routing methods: Priority (active/passive failover), Weighted (percentage-based distribution), Performance (lowest latency), Geographic (regulation compliance), Multivalue (multiple healthy endpoints), and Subnet (IP range mapping). Operates at the DNS layer, returning the appropriate endpoint FQDN without proxying traffic. Health probes continuously monitor endpoint availability and automatically remove unhealthy endpoints from rotation. Supports Azure, external, and nested endpoints for complex multi-region architectures. Consider Azure Front Door for Layer 7 features and faster failover.', bestPractice: 'Name pattern: traf-{workload}-{routing}. Include routing type (perf/geo/priority) for operational clarity.', namingGuidance: 'Name pattern: traf-{workload}-{routing}. Include the routing method (perf, geo, priority, weighted) as it directly affects the user experience and is critical for troubleshooting (e.g. traf-web-perf for performance routing, traf-api-priority for failover). The profile name becomes the DNS name ({name}.trafficmanager.net). For new deployments, evaluate Azure Front Door which offers faster failover and Layer 7 features.', learnUrl: 'https://learn.microsoft.com/azure/traffic-manager/traffic-manager-overview' },
    { category: 'Networking', name: 'Front Door', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=frontdoor', provider: 'Microsoft.Cdn/profiles', abbrev: 'fd', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Global Layer 7 load balancer with integrated CDN, WAF, SSL offload, and intelligent routing. Provides sub-second global failover and edge caching at 180+ PoPs.', longDesc: 'Global Layer 7 load balancer operating at Microsoft\'s edge network with integrated CDN, Web Application Firewall (WAF), SSL offload, and intelligent routing across 180+ Points of Presence (PoPs) worldwide. Provides sub-second failover between backends using real-time health probes, and edge caching for static content. Standard/Premium tiers unify CDN, WAF, and global load balancing into a single resource. Supports URL path-based routing, session affinity, and custom domain/TLS certificate management. Premium tier adds Private Link origin support, bot protection, and managed rule sets with anomaly scoring.', bestPractice: 'Name pattern: fd-{workload}-{purpose}. Resource name unique to RG; endpoint must be globally unique.', namingGuidance: 'Name pattern: fd-{workload}-{purpose}. The Front Door resource name is scoped to the resource group, but custom endpoints must be globally unique ({name}.azurefd.net). Include the workload and purpose in the resource name (e.g. fd-payments-web, fd-api-global). Use custom domains in production and configure WAF policies for all internet-facing endpoints.', learnUrl: 'https://learn.microsoft.com/azure/frontdoor/front-door-overview' },
    { category: 'Networking', name: 'Bastion host', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=azure-bastion', provider: 'Microsoft.Network/bastionHosts', abbrev: 'bas', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Fully managed PaaS providing secure RDP/SSH connectivity via browser or native client without VM public IPs. Supports session recording, shareable links, and file transfer.', longDesc: 'Fully managed PaaS providing secure RDP and SSH connectivity to VMs directly from the Azure portal (browser-based) or native RDP/SSH clients, eliminating the need for public IP addresses on VMs. Bastion acts as a jump server with TLS encryption from the user to the Bastion and SSH/RDP from Bastion to the target VM. Standard SKU adds host scaling, native client support, shareable links for third-party access, file transfer, and custom ports over Basic. Premium SKU adds session recording for compliance auditing and private-only deployment, removing the requirement for a public IP on the Bastion resource itself. Bastion is deployed in a dedicated AzureBastionSubnet (/26 minimum) and provides connectivity to all VMs in the same VNet and peered VNets.', bestPractice: 'Name pattern: bas-{vnet}-{region}. Deploy in AzureBastionSubnet; one per VNet for VM connectivity.', namingGuidance: 'Name pattern: bas-{vnet}-{region}. Deploy one Bastion per VNet (or per hub VNet for hub-spoke topologies) in a subnet named exactly AzureBastionSubnet (/26 or larger). Include the VNet name in the Bastion name for quick identification (e.g. bas-hub-uks, bas-spoke-app-weu). Standard SKU is recommended for most production workloads and adds native client support, shareable links, and file transfer over Basic. Premium adds session recording for compliance auditing and supports private-only deployment.', learnUrl: 'https://learn.microsoft.com/azure/bastion/bastion-overview' },
    { category: 'Networking', name: 'Network watcher', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=network-watcher', provider: 'Microsoft.Network/networkWatchers', abbrev: 'nw', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Network diagnostics platform with packet capture, connection troubleshoot, NSG flow logs, and topology visualization. Enables Traffic Analytics for security insights.', longDesc: 'Network diagnostics and monitoring platform providing tools for troubleshooting and analysing Azure network infrastructure. Key capabilities include packet capture (on VMs without installing agents), connection troubleshoot (testing connectivity between resources), IP flow verify (checking NSG rule evaluation), next hop (validating route tables), and VPN diagnostics. NSG flow logs record all traffic passing through NSGs, with Traffic Analytics providing rich visualisations of traffic patterns, bandwidth utilisation, and security insights. Network Watcher is automatically created per region when you have a virtual network.', bestPractice: 'Name pattern: NetworkWatcher_{region}. Auto-created per region by Azure; name is fixed and cannot be changed.', namingGuidance: 'Name pattern: NetworkWatcher_{region}. Network Watcher is automatically created by Azure when your first VNet is deployed in a region. The name is fixed to NetworkWatcher_{region} (e.g. NetworkWatcher_uksouth) and cannot be changed. The primary action item is enabling NSG flow logs and Traffic Analytics for security visibility rather than managing the watcher resource itself.', learnUrl: 'https://learn.microsoft.com/azure/network-watcher/network-watcher-monitoring-overview' },
    {
        category: 'Networking', name: 'DDoS protection plan', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=ddos-protection', provider: 'Microsoft.Network/ddosProtectionPlans', abbrev: 'ddos', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Protects Azure resources from Distributed Denial of Service (DDoS) attacks. Shield resources in virtual networks from DDoS attacks.', longDesc: 'Protects Azure resources in virtual networks from volumetric, protocol, and application-layer DDoS attacks with always-on traffic monitoring, adaptive tuning, and automatic attack mitigation. Provides advanced attack analytics, real-time metrics, and diagnostic logs integrated with Azure Monitor. DDoS Network Protection applies to all public IP resources in the associated VNet, including VMs, load balancers, application gateways, and Azure Firewall. Includes DDoS Rapid Response (DRR) team access during active attacks and cost protection guaranteeing credits for scale-out charges incurred during attacks. A single plan can protect up to 100 VNets across subscriptions in the same tenant.', bestPractice: 'Name pattern: ddos-{scope}-{region}. Create one plan per region and link multiple VNets.', namingGuidance: 'Name pattern: ddos-{scope}-{region}. A single DDoS plan can protect up to 100 VNets across subscriptions, so typically one per region is sufficient (e.g. ddos-org-uks, ddos-org-weu). Link all VNets in the region to the same plan. The plan is the most expensive network security resource, so sharing across VNets is the cost-effective approach. Use Azure DDoS IP Protection for individual public IP protection instead of a full plan.', learnUrl: 'https://learn.microsoft.com/azure/ddos-protection/ddos-protection-overview', subResources: [
            { suffix: 'vnet', label: 'Virtual Network', dnsZone: null },
            { suffix: 'hub', label: 'Hub Network', dnsZone: null },
            { suffix: 'spoke', label: 'Spoke Network', dnsZone: null }
        ]
    },

    // Storage
    { category: 'Storage', name: 'Storage account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=storage', provider: 'Microsoft.Storage/storageAccounts', abbrev: 'st', maxLength: 24, scope: 'Global', chars: 'a-z, 0-9', desc: 'Unified object storage supporting Blob, File, Queue, Table, and Data Lake. Choose from Standard (HDD/SSD) or Premium (SSD) performance, and LRS, ZRS, GRS, or GZRS redundancy for up to 16 nines of durability.', longDesc: 'Unified object storage supporting Blob, File, Queue, Table, and Data Lake services within a single account. Standard tier uses HDD-backed storage for cost-effective bulk storage, while Premium tier provides SSD-backed low-latency performance for high-transaction workloads. Redundancy options range from LRS (3 copies in one datacenter) to GZRS (6 copies across zones and regions) for up to 16 nines of durability. Storage accounts support lifecycle management policies, immutability policies for WORM compliance, and customer-managed encryption keys via Key Vault. Use private endpoints to restrict access to your virtual network.', bestPractice: 'Name pattern: st{workload}{env}{random}. Max 24 chars, no hyphens; add random suffix for global uniqueness.', namingGuidance: 'Name pattern: st{workload}{env}{random}. Storage account names are globally unique and limited to 24 lowercase characters with no hyphens or special characters — this is one of the most restrictive naming rules in Azure. Append a short random suffix (3-4 chars) to guarantee global uniqueness. Use a consistent prefix that identifies the workload and environment (e.g. stpaymentsprod7x2). For diagnostic/boot storage, use a dedicated account with a recognisable prefix like stdiag.', learnUrl: 'https://learn.microsoft.com/azure/storage/common/storage-account-overview' },
    { category: 'Storage', name: 'Azure Files share', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=storage', provider: 'Microsoft.Storage/storageAccounts/fileServices/shares', abbrev: 'share', maxLength: 63, scope: 'Storage account', chars: 'a-z, 0-9, -', desc: 'Cloud file share supporting SMB and NFS protocols. Naming rules are identical for both: 3-63 characters, lowercase letters, numbers, and hyphens (no consecutive).', longDesc: 'Cloud file share supporting SMB 3.x and NFS 4.1 protocols with fully managed provisioning and automatic tiering between hot, cool, and transaction-optimised tiers. SMB shares support Microsoft Entra ID authentication, on-premises AD DS integration, and access from Windows, macOS, and Linux. NFS shares are optimised for Linux workloads with POSIX file permissions and ACLs. Azure File Sync enables hybrid scenarios by caching frequently accessed data on-premises while tiering cold data to the cloud. Premium file shares provide SSD-backed performance with provisioned IOPS and throughput.', bestPractice: 'Name pattern: share-{storageaccount}-{purpose}. Include parent storage account name; lowercase only; must start/end with letter or number.', namingGuidance: 'Name pattern: share-{storageaccount}-{purpose}. File share names are limited to lowercase letters, numbers, and single hyphens (no consecutive hyphens). Include the parent storage account name for context and a purpose suffix (e.g. share-stpayments-logs, share-stmedia-uploads). Must start and end with a letter or number. For SMB shares requiring AD authentication, plan the share structure to align with your NTFS permission model.', learnUrl: 'https://learn.microsoft.com/azure/storage/files/storage-files-introduction' },
    { category: 'Storage', name: 'Data Lake Storage', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=storage', provider: 'Microsoft.Storage/storageAccounts', abbrev: 'dls', maxLength: 24, scope: 'Global', chars: 'a-z, 0-9', desc: 'Blob storage with hierarchical namespace (HNS) enabling POSIX-compliant file operations. Optimized for Spark, Hadoop, and analytics with fine-grained RBAC and ACLs.', longDesc: 'Blob storage enhanced with a hierarchical namespace (HNS) that enables POSIX-compliant file and directory operations with true rename and delete semantics (O(1) atomic operations instead of O(n) copy-delete). Optimised for big data analytics frameworks including Apache Spark, Hadoop, Azure Databricks, and Synapse Analytics. Supports fine-grained access control through RBAC, POSIX ACLs, and shared access signatures. HNS must be enabled at storage account creation and cannot be changed afterwards. Integrates with Azure Data Factory for ETL, Azure Synapse Analytics for SQL-over-files, and supports ADLS Gen2 REST API and ABFSS driver for Spark.', bestPractice: 'Name pattern: dls{workload}{env}. Max 24 chars, no hyphens; enable HNS at creation for analytics workloads.', namingGuidance: 'Name pattern: dls{workload}{env}. Data Lake Storage follows the same restrictive naming rules as regular storage accounts: 24 characters maximum, lowercase letters and numbers only, no hyphens. Add a random suffix for global uniqueness (e.g. dls analytics prod7x2). HNS must be enabled at creation and cannot be added later, so plan this decision upfront. Use dedicated storage accounts for data lake workloads rather than mixing with general-purpose storage.', learnUrl: 'https://learn.microsoft.com/azure/storage/blobs/data-lake-storage-introduction' },
    { category: 'Storage', name: 'NetApp account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=netapp', provider: 'Microsoft.NetApp/netAppAccounts', abbrev: 'anf', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Enterprise NAS service providing NetApp ONTAP features including snapshots, cloning, and cross-region replication. Supports NFSv3/NFSv4.1 and SMB 3.x with Active Directory integration.', longDesc: 'Enterprise NAS service providing NetApp ONTAP features natively in Azure, including instant snapshots (no performance impact), FlexClone for instant volume cloning, and cross-region replication for disaster recovery. Supports NFSv3, NFSv4.1, and SMB 3.x protocols with Active Directory integration for SMB shares. The account is the administrative grouping for capacity pools and volumes in a region. Performance is determined by the service level of the capacity pool (Standard, Premium, or Ultra) and the allocated quota per volume. Ideal for lift-and-shift of on-premises NAS workloads, SAP HANA, HPC, and media rendering.', bestPractice: 'Name pattern: anf-{workload}-{env}-{region}. One account per region; contains capacity pools and volumes.', namingGuidance: 'Name pattern: anf-{workload}-{env}-{region}. Deploy one ANF account per region as the account is a regional resource (e.g. anf-sap-prod-uks). The account serves as the top-level container for capacity pools and volumes. Use a naming convention that aligns the account with the primary workload it serves, especially for SAP HANA and HPC deployments where ANF performance tiers are specifically sized.', learnUrl: 'https://learn.microsoft.com/azure/azure-netapp-files/azure-netapp-files-introduction' },
    { category: 'Storage', name: 'NetApp capacity pool', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=netapp', provider: 'Microsoft.NetApp/netAppAccounts/capacityPools', abbrev: 'anfpool', maxLength: 64, scope: 'ANF account', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Provisioned capacity container with Standard/Premium/Ultra service levels determining throughput per TiB. Minimum 2TiB per pool with QoS auto or manual assignment.', longDesc: 'Provisioned capacity container within a NetApp account that defines the performance tier and available storage for volumes. Service levels determine throughput: Standard (16 MiB/s per TiB), Premium (64 MiB/s per TiB), and Ultra (128 MiB/s per TiB). Minimum pool size is 2 TiB (reduced from 4 TiB) with 1 TiB increments. QoS can be automatic (throughput proportional to volume quota) or manual (throughput explicitly set per volume). Volumes within a pool share the provisioned capacity but can have individual quotas. Cool access tiering optimises costs by moving infrequently accessed data to a cooler storage tier.', bestPractice: 'Name pattern: anfpool-{anfaccount}-{tier}. Include parent ANF account name; name by service level (std/prem/ultra) and workload.', namingGuidance: 'Name pattern: anfpool-{anfaccount}-{tier}. Include the parent ANF account name and service level tier for clear identification (e.g. anfpool-anf-sap-prod-ultra, anfpool-anf-media-dev-prem). The service level in the name immediately communicates the performance characteristics to operators. Choose between auto and manual QoS based on whether volumes need uniform or customised throughput allocation.', learnUrl: 'https://learn.microsoft.com/azure/azure-netapp-files/azure-netapp-files-set-up-capacity-pool' },
    { category: 'Storage', name: 'NetApp volume', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=netapp', provider: 'Microsoft.NetApp/netAppAccounts/capacityPools/volumes', abbrev: 'anfvol', maxLength: 64, scope: 'Capacity pool', chars: 'a-z, A-Z, 0-9, -, _', desc: 'NFS or SMB file share with snapshot policies, backup integration, and cross-region replication. Supports application-consistent snapshots for databases.', longDesc: 'NFS or SMB file share within a NetApp capacity pool, providing enterprise-grade storage with instant snapshots (no performance impact), snapshot policies for automated scheduling, and Azure NetApp Files backup for long-term retention. Cross-region replication enables disaster recovery with RPOs as low as 10 minutes. Supports application-consistent snapshots for SAP HANA and Oracle databases through integration with Azure Application Consistent Snapshot tool (AzAcSnap). Volume size ranges from 50 GiB to 100 TiB with dynamic quota adjustments. Dual-protocol volumes support both NFS and SMB access simultaneously.', bestPractice: 'Name pattern: anfvol-{pool}-{app}. Include parent capacity pool name and application name; enable snapshot policies.', namingGuidance: 'Name pattern: anfvol-{pool}-{app}. Include the parent capacity pool for hierarchy context and the application or data purpose (e.g. anfvol-ultra-saphana-data, anfvol-prem-media-renders). For SAP HANA deployments, use standardised suffixes: -data, -log, -shared, -backup. Enable snapshot policies immediately after volume creation to ensure data protection from day one.', learnUrl: 'https://learn.microsoft.com/azure/azure-netapp-files/azure-netapp-files-create-volumes' },

    // Web
    { category: 'Web', name: 'App Service plan', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=app-service', provider: 'Microsoft.Web/serverfarms', abbrev: 'asp', maxLength: 60, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Compute tier defining vCPU, memory, and features for App Service apps. Premium V3 provides VNet integration, zone redundancy, and 8-192 GB RAM options.', longDesc: 'Compute tier defining vCPU, memory, and features for App Service apps. An App Service plan is the server farm that hosts your web apps, API apps, and function apps. The Free and Shared tiers share underlying VMs, while Basic and above get dedicated compute. Premium V3 offers VNet integration for private access, zone redundancy for HA, and isolation for compliance. Multiple apps can share a single plan to reduce costs, but they compete for CPU and memory — separate plans for workloads with different scaling or compliance requirements.', bestPractice: 'Name pattern: asp-{workload}-{env}-{region}. Share plan across related apps; separate by workload/env for scaling.', namingGuidance: 'Name pattern: asp-{workload}-{env}-{region}. Group related apps on the same plan to share compute costs, but separate plans for workloads that need independent scaling or compliance isolation. Include the region since plans are regional resources. Use the same plan for staging deployment slots as their parent app — slots share the plan\'s compute allocation.', learnUrl: 'https://learn.microsoft.com/azure/app-service/overview-hosting-plans' },
    { category: 'Web', name: 'App Service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=app-service', provider: 'Microsoft.Web/sites', abbrev: 'app', maxLength: 60, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'PaaS for web apps supporting .NET, Java, Node.js, Python, PHP, and containers. Features built-in auto-scale, deployment slots for zero-downtime releases, and App Service Environments (ASE) for full isolation.', longDesc: 'Fully managed PaaS for hosting web apps, REST APIs, and mobile backends supporting .NET, Java, Node.js, Python, PHP, Ruby, and custom containers. Key features include deployment slots for blue-green zero-downtime releases, integrated authentication with Microsoft Entra ID (EasyAuth), and auto-scaling rules based on CPU, memory, or HTTP queue length. For enterprise workloads, App Service Environments (ASE v3) provide single-tenant compute in your own VNet with dedicated front-ends. Custom domains and managed SSL certificates are supported on all paid tiers.', bestPractice: 'Name pattern: app-{workload}-{purpose}-{env}. Globally unique; becomes {name}.azurewebsites.net hostname.', namingGuidance: 'Name pattern: app-{workload}-{purpose}-{env}. The name must be globally unique as it forms the default hostname {name}.azurewebsites.net. Include a purpose suffix (web, api, portal, admin) when you have multiple App Service instances within the same workload. Map custom domains for production — the default hostname should still be meaningful for dev/staging environments where custom domains may not be configured.', learnUrl: 'https://learn.microsoft.com/azure/app-service/overview' },
    { category: 'Web', name: 'Static Web App', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=static-web-apps', provider: 'Microsoft.Web/staticSites', abbrev: 'stapp', maxLength: 60, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Globally distributed hosting for static web apps (React, Vue, Angular) with integrated serverless APIs, automated CI/CD workflows, and preview environments.', longDesc: 'Azure Static Web Apps provides globally distributed hosting for static content and single-page applications (SPAs) with integrated serverless APIs. It features seamless continuous integration and continuous deployment (CI/CD) natively through GitHub Actions or Azure DevOps. The service automatically builds and deploys your app on every push, provisions preview environments for pull requests, and automatically manages SSL certificates for custom domains. Standard tier unlocks enterprise features like private endpoints for backend integration and custom authentication.', bestPractice: 'Name pattern: stapp-{workload}-{env}. Include purpose; auto-deploys from GitHub/DevOps on push.', namingGuidance: 'Name pattern: stapp-{workload}-{env}. For deployment, rely on the native GitHub Actions or Azure DevOps integration for automated CI/CD. Utilize the Azure Static Web Apps CLI (SWA CLI) for local development to emulate authentication and API routing before deploying. Use the Standard tier in production to securely connect your backend APIs via Private Link.', learnUrl: 'https://learn.microsoft.com/azure/static-web-apps/overview' },
    { category: 'Web', name: 'API Management', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=api-management', provider: 'Microsoft.ApiManagement/service', abbrev: 'apim', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Full-lifecycle API gateway with rate limiting, OAuth/JWT validation, caching, and developer portal. Supports OpenAPI import, policy expressions, and multi-region deployment.', longDesc: 'Full-lifecycle API management platform providing a unified gateway for internal and external API consumers. Key features include rate limiting and throttling, OAuth 2.0 and JWT token validation, response caching, request/response transformation via policy expressions, and a built-in developer portal for API documentation and onboarding. Supports importing APIs from OpenAPI specifications, WSDL files, Azure Functions, App Services, and Logic Apps. Multi-region deployment capability enables low-latency API access globally. The self-hosted gateway extends API Management to hybrid and multi-cloud environments running as a Kubernetes container.', bestPractice: 'Name pattern: apim-{workload}-{env}-{region}-{instance}. Globally unique; keep concise.', namingGuidance: 'Name pattern: apim-{workload}-{env}-{region}-{instance}. The name is globally unique and forms the gateway URL ({name}.azure-api.net) and developer portal URL ({name}.developer.azure-api.net). Following the Cloud Adoption Framework, use the standard 5-part convention (e.g. apim-orders-prod-weu-001). The 50-character limit means you should keep your workload abbreviations concise. Separate production and development instances for workload isolation.', learnUrl: 'https://learn.microsoft.com/azure/api-management/api-management-key-concepts' },

    // Databases
    { category: 'Databases', name: 'SQL server', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=sql-database', provider: 'Microsoft.Sql/servers', abbrev: 'sql', maxLength: 63, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'Logical server container for Azure SQL databases with shared connection policies and firewall rules. Supports Microsoft Entra ID authentication and transparent data encryption.', longDesc: 'Logical server container for Azure SQL databases, elastic pools, and Synapse SQL pools. The logical server defines shared connection policies, firewall rules, auditing settings, and the authentication method (SQL auth, Microsoft Entra ID, or both). Transparent Data Encryption (TDE) is enabled by default for data-at-rest protection. All databases on the server share the same endpoint ({name}.database.windows.net) and can leverage failover groups for geo-distributed HA. Use virtual network rules or private endpoints to restrict access to your VNet.', bestPractice: 'Name pattern: sql-{workload}-{env}. Globally unique; hosts multiple databases; use Entra ID auth.', namingGuidance: 'Name pattern: sql-{workload}-{env}. The server name is globally unique and forms the connection endpoint {name}.database.windows.net. Group related databases on the same server to share connection policies and firewall rules. Use Microsoft Entra ID authentication (formerly Azure AD) as the primary auth method with SQL auth disabled for security. For disaster recovery, configure auto-failover groups which provide a separate listener endpoint.', learnUrl: 'https://learn.microsoft.com/azure/azure-sql/database/sql-database-paas-overview' },
    { category: 'Databases', name: 'SQL database', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=sql-database', provider: 'Microsoft.Sql/servers/databases', abbrev: 'sqldb', maxLength: 128, scope: 'Server', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Fully managed relational database with 99.995%+ SLA. Purchasing models include vCore (flexibility/control) and DTU (bundled performance). usage patterns.', longDesc: 'Fully managed relational database engine based on the latest stable version of SQL Server, providing 99.995%+ SLA with zone-redundant configurations. Two purchasing models: vCore (independent compute and storage scaling, Azure Hybrid Benefit eligible) and DTU (bundled CPU, memory, and I/O for simple sizing). Supports Hyperscale tier for databases up to 100 TB with near-instant backups and rapid scale-out read replicas. Built-in intelligence provides automatic tuning, threat detection, and vulnerability assessment. Ledger tables provide tamper-evident data integrity for audit and compliance scenarios.', bestPractice: 'Name pattern: sqldb-{sqlserver}-{purpose}. Include parent SQL server name and database purpose; use elastic pool for multi-tenant.', namingGuidance: 'Name pattern: sqldb-{sqlserver}-{purpose}. Include the parent SQL server name for hierarchical context and the database purpose (e.g. sqldb-sql-payments-orders, sqldb-sql-crm-contacts). For multi-tenant SaaS applications, use elastic pools to share resources. The 128-character limit is generous, so use descriptive names that clearly identify the data domain and ownership.', learnUrl: 'https://learn.microsoft.com/azure/azure-sql/database/sql-database-paas-overview' },
    { category: 'Databases', name: 'SQL elastic pool', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=sql-database', provider: 'Microsoft.Sql/servers/elasticPools', abbrev: 'sqlep', maxLength: 128, scope: 'Server', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Shared DTU/vCore resource pool for multiple databases with unpredictable usage patterns. Enables cost-effective multi-tenancy with per-database min/max resource limits.', longDesc: 'Shared compute and storage resource pool for multiple Azure SQL databases with unpredictable or bursty usage patterns. Instead of provisioning each database independently, elastic pools share DTUs or vCores across all member databases, allowing individual databases to burst up to the pool maximum while the overall cost remains predictable. Per-database minimum and maximum resource limits prevent any single database from consuming all pool resources. Ideal for SaaS multi-tenant architectures where tenant databases have similar schemas but variable workloads. Supports up to 500 databases per pool in DTU model and flexible limits in vCore model.', bestPractice: 'Name pattern: sqlep-{sqlserver}-{workload}. Include parent SQL server name; pool databases with similar usage patterns for cost efficiency.', namingGuidance: 'Name pattern: sqlep-{sqlserver}-{workload}. Include the parent SQL server name and the workload or tenant group the pool serves (e.g. sqlep-sql-payments-tenants, sqlep-sql-crm-reporting). Pool databases with similar peak/off-peak patterns together for optimal resource sharing. Monitor eDTU/vCore utilisation to right-size the pool and adjust per-database min/max settings.', learnUrl: 'https://learn.microsoft.com/azure/azure-sql/database/elastic-pool-overview' },
    { category: 'Databases', name: 'SQL Managed Instance', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=sql-managed-instance', provider: 'Microsoft.Sql/managedInstances', abbrev: 'sqlmi', maxLength: 63, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'VNet-integrated SQL Server instance with near 100% feature parity including SQL Agent, CLR, and cross-database queries. Supports native backup/restore from on-premises SQL Server.', longDesc: 'Fully managed SQL Server instance deployed directly into your VNet with near 100% compatibility with on-premises SQL Server Enterprise Edition. Supports features unavailable in SQL Database including SQL Server Agent, CLR integration, cross-database queries, distributed transactions, linked servers, and Database Mail. Native backup/restore using .bak files simplifies migration from on-premises SQL Server. Requires a dedicated subnet (/27 minimum with 32 addresses) in your VNet. Auto-failover groups provide geo-redundant HA with a separate listener endpoint for transparent application failover.', bestPractice: 'Name pattern: sqlmi-{workload}-{env}. Globally unique; requires dedicated subnet (/27 minimum).', namingGuidance: 'Name pattern: sqlmi-{workload}-{env}. The name is globally unique and forms the connection endpoint ({name}.{dnszone}.database.windows.net). Use descriptive workload names (e.g. sqlmi-erp-prod, sqlmi-legacy-migration-dev). The instance requires a dedicated subnet with at least a /27 CIDR, so plan VNet addressing accordingly. For migration scenarios, the name should reflect the target workload rather than the source server name.', learnUrl: 'https://learn.microsoft.com/azure/azure-sql/managed-instance/sql-managed-instance-paas-overview' },
    { category: 'Databases', name: 'Cosmos DB account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cosmos-db', provider: 'Microsoft.DocumentDB/databaseAccounts', abbrev: 'cosmos', maxLength: 44, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'Globally distributed multi-model database with single-digit millisecond latency and 99.999% availability. Supports SQL, MongoDB, Cassandra, Gremlin, and Table APIs with tunable consistency.', longDesc: 'Globally distributed multi-model database with single-digit millisecond latency at the 99th percentile and up to 99.999% availability with multi-region writes. Supports five API interfaces: NoSQL (SQL), MongoDB, Cassandra, Gremlin (graph), and Table — each with wire-protocol compatibility. Offers five tunable consistency levels from Strong to Eventual, enabling precise trade-offs between consistency, availability, and throughput. Autoscale RU/s automatically adjusts throughput between 10-100% of the configured maximum based on workload demand. Synapse Link provides no-ETL analytics directly over operational data.', bestPractice: 'Name pattern: cosmos-{workload}-{env}. Globally unique; choose API at creation; use autoscale RU/s.', namingGuidance: 'Name pattern: cosmos-{workload}-{env}. The account name is globally unique and limited to 44 characters. The API (NoSQL, MongoDB, etc.) is chosen at account creation and cannot be changed afterwards, so include it in the name only if you run multiple APIs for the same workload (e.g. cosmos-payments-sql-prod). For most workloads a single account per environment is sufficient — databases and containers provide the internal namespace. Use autoscale RU/s to avoid over-provisioning.', learnUrl: 'https://learn.microsoft.com/azure/cosmos-db/introduction' },
    { category: 'Databases', name: 'MySQL server', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=mysql', provider: 'Microsoft.DBforMySQL/flexibleServers', abbrev: 'mysql', maxLength: 63, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'Fully managed MySQL 5.7/8.0 with up to 99.99% SLA, automated backups, and point-in-time restore. Flexible Server offers zone-redundant HA and same-zone read replicas.', longDesc: 'Fully managed MySQL 5.7 and 8.0 database service with automated backups, point-in-time restore (up to 35 days), and up to 99.99% SLA. Flexible Server (the recommended deployment model) offers zone-redundant high availability with automatic failover, same-zone read replicas for read scale-out, and VNet integration via delegated subnet. Compute tiers range from Burstable (B-series) for dev/test to Business Critical (E-series) for high-performance production workloads. Supports data-in replication from on-premises MySQL servers for hybrid scenarios and migration.', bestPractice: 'Name pattern: mysql-{workload}-{env}. Globally unique; use Flexible Server for new deployments.', namingGuidance: 'Name pattern: mysql-{workload}-{env}. The server name is globally unique and forms the connection endpoint ({name}.mysql.database.azure.com). Use Flexible Server for all new deployments — Single Server is on the deprecation path. Include workload and environment for clear identification (e.g. mysql-cms-prod, mysql-ecommerce-staging). Configure VNet integration via delegated subnet for production workloads rather than public access with firewall rules.', learnUrl: 'https://learn.microsoft.com/azure/mysql/overview' },
    { category: 'Databases', name: 'PostgreSQL server', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=postgresql', provider: 'Microsoft.DBforPostgreSQL/flexibleServers', abbrev: 'psql', maxLength: 63, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'Fully managed PostgreSQL 11-16 with intelligent performance tuning and pgvector extension for AI workloads. Supports Citus extension for horizontal scale-out to 100+ nodes.', longDesc: 'Fully managed PostgreSQL 11 through 16 with intelligent performance tuning, automated maintenance, and rich extension support including pgvector for AI/ML vector similarity search and PostGIS for geospatial queries. Flexible Server offers zone-redundant HA, same-zone read replicas, and VNet integration. The Citus extension enables horizontal scale-out across 100+ nodes for multi-tenant SaaS, real-time analytics, and time-series workloads. Intelligent tuning automatically creates and validates indexes based on query patterns. Supports major version in-place upgrades and logical replication for migration.', bestPractice: 'Name pattern: psql-{workload}-{env}. Globally unique; use Flexible Server with HA for production.', namingGuidance: 'Name pattern: psql-{workload}-{env}. The server name is globally unique and forms the connection endpoint ({name}.postgres.database.azure.com). Use Flexible Server for all new deployments (e.g. psql-orders-prod, psql-analytics-staging). For AI/ML workloads using pgvector, include a hint in the name (e.g. psql-embeddings-prod). Configure VNet integration for production and enable HA for critical databases.', learnUrl: 'https://learn.microsoft.com/azure/postgresql/overview' },
    { category: 'Databases', name: 'Azure Cache for Redis', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cache', provider: 'Microsoft.Cache/redis', abbrev: 'redis', maxLength: 63, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'In-memory data store supporting Redis 6.x with clustering, geo-replication, and data persistence. Premium tier offers sub-millisecond latency with up to 120GB cache.', longDesc: 'Fully managed in-memory data store based on Redis 6.x providing sub-millisecond read/write latency for caching, session management, real-time analytics, and message brokering. Premium tier offers clustering (up to 10 shards for 120 GB aggregate cache), active geo-replication for globally distributed caching, data persistence (RDB snapshots and AOF logging), and VNet isolation. Enterprise tier adds Redis Modules including RediSearch (full-text search), RedisTimeSeries, and RedisBloom (probabilistic data structures). Common use cases include database query caching, session state storage, leaderboards, and pub/sub messaging.', bestPractice: 'Name pattern: redis-{workload}-{env}. Globally unique; use Premium tier for VNet and persistence.', namingGuidance: 'Name pattern: redis-{workload}-{env}. The name is globally unique and forms the connection endpoint ({name}.redis.cache.windows.net). Include workload and environment for clear identification (e.g. redis-payments-prod, redis-sessions-staging). Use Premium tier for production workloads requiring VNet isolation and data persistence. For globally distributed applications, configure active geo-replication across regions.', learnUrl: 'https://learn.microsoft.com/azure/azure-cache-for-redis/cache-overview' },

    // Containers
    { category: 'Containers', name: 'Kubernetes (AKS)', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=kubernetes-service', provider: 'Microsoft.ContainerService/managedClusters', abbrev: 'aks', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Managed Kubernetes with automated patching and scaling. Supports multiple node pools (system/user), virtual nodes for burst, and Azure RBAC for secure cluster access.', longDesc: 'Managed Kubernetes service with automated control plane patching, node OS updates, and cluster scaling. AKS supports multiple node pools — system pools for core Kubernetes components and user pools for application workloads — enabling heterogeneous compute (CPU, GPU, memory-optimised) within a single cluster. Azure RBAC integration provides granular namespace-level access control without managing Kubernetes RBAC directly. Key enterprise features include Azure CNI Overlay networking, Microsoft Defender for Containers, and workload identity for pod-level managed identity. Use KEDA for event-driven autoscaling and GitOps with Flux for declarative cluster configuration.', bestPractice: 'Name pattern: aks-{workload}-{env}-{region}. Use separate node pools; AKS name becomes DNS prefix.', namingGuidance: 'Name pattern: aks-{workload}-{env}-{region}. The cluster name becomes the DNS prefix for the API server endpoint ({name}-dns-{hash}.hcp.{region}.azmk8s.io). Include the region since AKS clusters are regional resources. Use descriptive workload names to distinguish multiple clusters — avoid generic names like aks-dev. AKS automatically creates a managed resource group (MC_{rg}_{cluster}_{region}) for node infrastructure; this cannot be customised after creation.', learnUrl: 'https://learn.microsoft.com/azure/aks/intro-kubernetes' },
    { category: 'Containers', name: 'Container registry', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=container-registry', provider: 'Microsoft.ContainerRegistry/registries', abbrev: 'cr', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9', desc: 'Geo-replicated Docker registry with OCI artifact support, content trust, and vulnerability scanning. Premium SKU offers private endpoints, CMK encryption, and 500 GiB storage.', longDesc: 'Geo-replicated Docker and OCI registry with enterprise features including content trust (image signing), automated vulnerability scanning via Microsoft Defender, and ACR Tasks for automated image builds triggered by source code commits or base image updates. Premium SKU adds geo-replication across Azure regions for low-latency pulls, private endpoints for VNet-restricted access, customer-managed key (CMK) encryption, and 500 GiB storage. Supports Helm charts, Singularity images, and other OCI artifacts alongside container images. Integrate with AKS using managed identity for seamless, credential-free image pulls.', bestPractice: 'Name pattern: cr{workload}{env}{region}{instance}. No hyphens allowed; globally unique.', namingGuidance: 'Name pattern: cr{workload}{env}{region}{instance}. Container registry names cannot contain hyphens, underscores, or special characters — only alphanumeric characters are allowed. The name forms the login server URL {name}.azurecr.io and must be globally unique. Following the Cloud Adoption Framework, use the standard 5-part convention without hyphens (e.g. crnavigatorprod001). Create separate registries per environment for strict isolation, or use repository-level RBAC to control access within a shared registry.', learnUrl: 'https://learn.microsoft.com/azure/container-registry/container-registry-intro' },
    { category: 'Containers', name: 'Container instance', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=container-instances', provider: 'Microsoft.ContainerInstance/containerGroups', abbrev: 'ci', maxLength: 63, scope: 'Resource group', chars: 'a-z, 0-9, -', desc: 'Serverless container execution with per-second billing and VNet deployment support. Offers up to 16 vCPU and 64 GB memory per container group with GPU options.', longDesc: 'Serverless container execution with per-second billing and no infrastructure management. Offers up to 16 vCPU and 64 GB memory per container group with optional NVIDIA GPU support for ML inference workloads. Container groups (similar to Kubernetes pods) can contain multiple containers sharing the same lifecycle, network, and storage. Supports VNet deployment for private access, Azure Files mounting for persistent storage, and restart policies (Always, OnFailure, Never) for different workload types. Ideal for burst computing, batch jobs, CI/CD build agents, and sidecar patterns.', bestPractice: 'Name pattern: ci-{workload}-{purpose}. Use for burst/batch workloads; name reflects job or function.', namingGuidance: 'Name pattern: ci-{workload}-{purpose}. Name container instances after the job or function they perform (e.g. ci-render-batch, ci-migration-runner, ci-build-agent). For ephemeral workloads, include a timestamp or run ID in the name. Container instances are best for short-lived or burst workloads — for long-running services, use Container Apps or AKS instead.', learnUrl: 'https://learn.microsoft.com/azure/container-instances/container-instances-overview' },
    { category: 'Containers', name: 'Container App', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=container-apps', provider: 'Microsoft.App/containerApps', abbrev: 'aca', maxLength: 32, scope: 'Environment', chars: 'a-z, 0-9, -', desc: 'Serverless container platform with KEDA-based autoscaling, Dapr integration, and revision management. Supports traffic splitting, mTLS, and built-in ingress with custom domains.', longDesc: 'Serverless container platform built on Kubernetes providing KEDA-based autoscaling (including scale-to-zero), Dapr integration for microservice building blocks, and revision-based deployment management. Supports traffic splitting between revisions for canary deployments, mutual TLS between apps for zero-trust networking, and built-in HTTPS ingress with custom domains. Container Apps abstract away the underlying Kubernetes complexity while still supporting any container image — you bring your own image from any registry. Ideal for microservices, APIs, event-driven processors, and background jobs without managing Kubernetes clusters.', bestPractice: 'Name pattern: aca-{service}-{env}. Max 32 chars; microservice name; uses FQDN {name}.{env}.azurecontainerapps.io.', namingGuidance: 'Name pattern: aca-{service}-{env}. Container App names are limited to 32 characters and form part of the FQDN ({name}.{envdomain}.azurecontainerapps.io). Name the app after the microservice it represents (e.g. aca-orders-api, aca-payment-worker). The environment is already encoded in the domain, so including it in the app name is optional but can aid portal navigation. Use revision labels for traffic splitting between deployment versions.', learnUrl: 'https://learn.microsoft.com/azure/container-apps/overview' },
    { category: 'Containers', name: 'Container Apps Environment', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=container-apps', provider: 'Microsoft.App/managedEnvironments', abbrev: 'cae', maxLength: 32, scope: 'Resource group', chars: 'a-z, 0-9, -', desc: 'Secure boundary with shared Log Analytics, VNet, and workload profiles for Container Apps. Consumption or dedicated compute options per environment.', longDesc: 'Secure boundary and shared infrastructure for one or more Container Apps, providing a common Log Analytics workspace, VNet configuration, and workload profiles. Consumption environments use shared multi-tenant infrastructure with per-second billing and scale-to-zero support. Dedicated workload profiles provide reserved compute for predictable performance and compliance requirements. All apps within an environment share the same subnet, enabling service discovery via internal DNS. The environment determines the availability zone configuration and can be configured with a custom domain suffix.', bestPractice: 'Name pattern: cae-{workload}-{env}. Max 32 chars. One per workload group; contains related container apps.', namingGuidance: 'Name pattern: cae-{workload}-{env}. Group related microservices in the same environment for service discovery and shared observability (e.g. cae-payments-prod, cae-ecommerce-staging). Environment names are limited to 32 characters. Create separate environments for workloads with different security, networking, or scaling requirements. The environment determines the domain suffix for all contained apps, so plan naming at the environment level.', learnUrl: 'https://learn.microsoft.com/azure/container-apps/environment' },

    // Security
    { category: 'Security', name: 'Key vault', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=key-vault', provider: 'Microsoft.KeyVault/vaults', abbrev: 'kv', maxLength: 24, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'HSM-backed secrets, keys, and certificate management. Features "Soft Delete" and "Purge Protection" to prevent data loss. Integrates with Azure Monitor for access logging.', longDesc: 'Centralised secrets, encryption keys, and certificate management backed by FIPS 140-2 Level 2 validated Hardware Security Modules (HSMs). Soft Delete (enabled by default) retains deleted vaults and objects for a configurable retention period, while Purge Protection prevents permanent deletion during the retention window — both are critical for production workloads. RBAC-based access control (recommended over access policies) provides granular permission management. Integrates with Azure Monitor and Microsoft Sentinel for access logging and anomaly detection. Supports automatic certificate renewal with DigiCert and GlobalSign CAs.', bestPractice: 'Name pattern: kv-{workload}-{env}. Max 24 chars; globally unique; one per workload/env for isolation.', namingGuidance: 'Name pattern: kv-{workload}-{env}. Key Vault names are globally unique and limited to 24 characters, making this one of the more restrictive naming rules. Use short abbreviations for workload and environment. The CAF recommends one vault per workload per environment for blast-radius isolation — never share a production vault with development. Enable RBAC authorization mode (instead of access policies) for fine-grained, auditable permission management. Enable diagnostic logging to a Log Analytics workspace.', learnUrl: 'https://learn.microsoft.com/azure/key-vault/general/overview' },
    { category: 'Security', name: 'Managed identity (user)', provider: 'Microsoft.ManagedIdentity/userAssignedIdentities', abbrev: 'id', maxLength: 128, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Azure AD identity assignable to multiple resources for credential-free authentication. Supports RBAC assignments and federation with external identity providers.', longDesc: 'User-assigned managed identity in Microsoft Entra ID (Azure AD) that provides credential-free authentication for Azure resources. Unlike system-assigned identities which are tied to a single resource, user-assigned identities can be shared across multiple resources (VMs, App Services, Functions, AKS pods) and persist independently of the resources using them. Supports RBAC role assignments on target resources (e.g. Key Vault Secrets User, Storage Blob Reader) and workload identity federation with external identity providers (GitHub Actions, Kubernetes, other clouds) for cross-platform scenarios.', bestPractice: 'Name pattern: id-{workload}-{purpose}. Create per application/purpose; assign RBAC at target resources.', namingGuidance: 'Name pattern: id-{workload}-{purpose}. Create one identity per application or microservice purpose (e.g. id-payments-api, id-etl-pipeline, id-github-deploy). This follows the principle of least privilege — each identity receives only the RBAC roles needed for its specific function. Avoid creating shared identities across workloads as this increases blast radius. Use workload identity federation for CI/CD pipelines to eliminate stored secrets entirely.', learnUrl: 'https://learn.microsoft.com/entra/identity/managed-identities-azure-resources/overview' },
    { category: 'Security', name: 'Key Vault Managed HSMs', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=key-vault', provider: 'Microsoft.KeyVault/managedHSMs', abbrev: 'kvmhsm', maxLength: 24, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'FIPS 140-3 Level 3 validated single-tenant HSM with full key administrative control. Supports customer security domain backup and restore for disaster recovery.', longDesc: 'Single-tenant, FIPS 140-3 Level 3 validated Hardware Security Module providing full administrative control over the cryptographic key lifecycle. Unlike standard Key Vault (FIPS 140-2 Level 2), Managed HSM offers dedicated HSM partitions with customer-exclusive access and the ability to back up and restore the security domain for disaster recovery. High throughput makes it suitable for TLS termination and database encryption at scale. The security domain is a unique encrypted blob that allows you to recover the HSM to a different instance — critical for business continuity. Required for PCI DSS, HIPAA, and FedRAMP High compliance.', bestPractice: 'Name pattern: kvmhsm-{org}-{env}. Max 24 chars; globally unique; use for regulated workloads (PCI/HIPAA).', namingGuidance: 'Name pattern: kvmhsm-{org}-{env}. Managed HSM names are globally unique and limited to 24 characters. Use concise organisation and environment abbreviations (e.g. kvmhsm-contoso-prod, kvmhsm-acme-pci). Deploy Managed HSM only when FIPS 140-3 Level 3 compliance is a hard requirement — standard Key Vault (FIPS 140-2 Level 2) is sufficient for most workloads at lower cost. Always download and securely store the security domain backup immediately after provisioning.', learnUrl: 'https://learn.microsoft.com/azure/key-vault/managed-hsm/overview' },
    { category: 'Security', name: 'Application Gateway WAF policy', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=web-application-firewall', provider: 'Microsoft.Network/ApplicationGatewayWebApplicationFirewallPolicies', abbrev: 'waf', maxLength: 128, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'OWASP Core Rule Set protection with custom rules, bot protection, and geo-filtering. Supports rate limiting, IP reputation, and JSON/XML payload inspection.', longDesc: 'Web Application Firewall policy providing OWASP Core Rule Set (CRS 3.2) protection against common web vulnerabilities including SQL injection, cross-site scripting (XSS), and command injection. Supports custom rules for IP allowlisting/blocklisting, geo-filtering by country, rate limiting per client IP, and header/query-string-based matching. Bot protection (Premium) identifies and blocks known malicious bots while allowing legitimate crawlers. Operates in Detection mode (logging only) or Prevention mode (blocking requests). A single WAF policy can be associated with multiple Application Gateway or Front Door instances for consistent security.', bestPractice: 'Name pattern: waf-{agw|fd}-{purpose}. Reference parent AGW/Front Door; use Detection mode first to tune.', namingGuidance: 'Name pattern: waf-{agw|fd}-{purpose}. Include the parent resource type (agw for Application Gateway, fd for Front Door) and the workload purpose (e.g. waf-agw-payments-prod, waf-fd-public-web). Always start in Detection mode to identify false positives before switching to Prevention mode. Keep custom rule priorities and exclusion lists documented as the WAF policy name alone cannot convey complex rule configurations.', learnUrl: 'https://learn.microsoft.com/azure/web-application-firewall/ag/policy-overview' },

    // Integration
    { category: 'Integration', name: 'Service Bus namespace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=service-bus', provider: 'Microsoft.ServiceBus/namespaces', abbrev: 'sbns', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Enterprise messaging with queues (point-to-point) and topics (pub/sub) supporting AMQP, HTTP, and JMS protocols. Premium tier offers message units for predictable throughput and VNet isolation.', longDesc: 'Enterprise messaging platform providing reliable queues (point-to-point) and topics (publish-subscribe) with support for AMQP 1.0, HTTP, and JMS 2.0 protocols. Messages persist durably and support dead-lettering for poison message handling, duplicate detection using message IDs, and sessions for ordered FIFO processing. Premium tier offers dedicated messaging units for predictable throughput, VNet isolation, and messages up to 100 MB. Supports transactions for atomic multi-operation processing and auto-forwarding for message chaining between entities. Ideal for decoupling microservices, distributed transactions, and event-driven architectures.', bestPractice: 'Name pattern: sbns-{workload}-{env}. Globally unique; contains queues/topics; use Premium for production.', namingGuidance: 'Name pattern: sbns-{workload}-{env}. The namespace name is globally unique and forms the endpoint ({name}.servicebus.windows.net). Use Premium tier for production workloads requiring predictable throughput and VNet isolation. Include workload and environment for clear identification (e.g. sbns-payments-prod, sbns-orders-staging). Queues and topics within the namespace provide the granular naming (e.g. order-created, payment-processed).', learnUrl: 'https://learn.microsoft.com/azure/service-bus-messaging/service-bus-messaging-overview' },
    { category: 'Integration', name: 'Service Bus queue', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=service-bus', provider: 'Microsoft.ServiceBus/namespaces/queues', abbrev: 'sbq', maxLength: 260, scope: 'Namespace', chars: 'a-z, A-Z, 0-9, -, _, ., /', desc: 'FIFO message queue with dead-lettering, duplicate detection, and sessions for ordered processing. Supports messages up to 256KB (Standard) or 100MB (Premium).', longDesc: 'FIFO message queue providing at-least-once or at-most-once delivery semantics with dead-letter sub-queue for poison message handling. Sessions enable ordered FIFO processing grouped by session ID — essential for maintaining message order in multi-consumer scenarios. Duplicate detection using a configurable time window prevents identical messages from being processed twice. Message lock duration is configurable (default 30 seconds) for long-processing consumers. Supports scheduled delivery for deferred processing and auto-forwarding to chain queues together. Max message size is 256 KB (Standard) or 100 MB (Premium).', bestPractice: 'Name pattern: sbq-{namespace}-{purpose}. Include parent Service Bus namespace name; enable sessions for ordered processing.', namingGuidance: 'Name pattern: sbq-{namespace}-{purpose}. Include the parent namespace name for context and name the queue after the message type or business process it handles (e.g. sbq-sbns-payments-order-created, sbq-sbns-notifications-email-send). Use domain-driven naming that reflects the bounded context. Enable sessions when message ordering is required and dead-lettering for poison message investigation.', learnUrl: 'https://learn.microsoft.com/azure/service-bus-messaging/service-bus-queues-topics-subscriptions' },
    { category: 'Integration', name: 'Service Bus topic', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=service-bus', provider: 'Microsoft.ServiceBus/namespaces/topics', abbrev: 'sbt', maxLength: 260, scope: 'Namespace', chars: 'a-z, A-Z, 0-9, -, _, ., /', desc: 'Publish-subscribe messaging with filter-based subscriptions for selective message routing. Supports SQL and correlation filters for complex routing scenarios.', longDesc: 'Publish-subscribe messaging pattern where publishers send messages to a topic and subscribers receive copies through subscriptions with optional filters. SQL filters evaluate message properties using SQL-like expressions for complex routing logic, while correlation filters provide faster property-based matching. Each subscription acts as a virtual queue with its own cursor, enabling multiple consumers to process the same messages independently. Supports forwarding to chain subscriptions to queues or other topics, session-based subscriptions for ordered processing, and dead-lettering at the subscription level. Ideal for fan-out scenarios where multiple services need to react to the same event.', bestPractice: 'Name pattern: sbt-{namespace}-{message-type}. Include parent Service Bus namespace name; create subscriptions per consumer.', namingGuidance: 'Name pattern: sbt-{namespace}-{message-type}. Name topics after the event or message type they carry (e.g. sbt-sbns-payments-order-completed, sbt-sbns-inventory-stock-updated). Create one subscription per consumer service, named after the consuming service (e.g. notifications-email, billing-invoice). This approach creates a clear, self-documenting messaging topology.', learnUrl: 'https://learn.microsoft.com/azure/service-bus-messaging/service-bus-queues-topics-subscriptions' },
    { category: 'Integration', name: 'Event Grid topic', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=event-grid', provider: 'Microsoft.EventGrid/topics', abbrev: 'evgt', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Serverless event routing with push-based delivery at 10M events/sec per topic. Supports CloudEvents schema, dead-lettering, and retry policies with exponential backoff.', longDesc: 'Serverless event routing service with push-based delivery capable of 10 million events per second per custom topic. Supports CloudEvents 1.0 schema for interoperability, dead-lettering to Blob Storage for failed deliveries, and configurable retry policies with exponential backoff. Custom topics enable your applications to publish events to a single endpoint, with subscribers filtering by event type or subject prefix. System topics automatically capture events from Azure services (Blob Storage, Resource Manager, etc.) without custom publisher code. Integrates with webhooks, Azure Functions, Event Hubs, Service Bus, and Storage Queues as event handlers.', bestPractice: 'Name pattern: evgt-{source}-{env}. Name by event source; configure dead-letter for failed deliveries.', namingGuidance: 'Name pattern: evgt-{source}-{env}. Name custom topics after the event source or domain they represent (e.g. evgt-orders-prod, evgt-user-registration-staging). System topics are auto-named after the source resource. Configure dead-letter destinations for all production subscriptions to capture failed deliveries. Use event type filtering and subject prefix filtering to route events efficiently to the correct handlers.', learnUrl: 'https://learn.microsoft.com/azure/event-grid/overview' },
    { category: 'Integration', name: 'Event Grid domain', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=event-grid', provider: 'Microsoft.EventGrid/domains', abbrev: 'evgd', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Multi-tenant event routing container supporting up to 100,000 topics per domain. Enables single endpoint for publishing events to multiple topics with per-topic authorization.', longDesc: 'Multi-tenant event routing container supporting up to 100,000 topics per domain, designed for SaaS applications and systems that need to route events to many independently managed topics through a single endpoint. Publishers send events to the domain endpoint with a topic specified in the event data, eliminating the need to manage individual topic endpoints. Per-topic authorization via RBAC enables tenant-level access control. Domains support the same delivery mechanisms as regular topics — webhooks, Functions, Event Hubs, and Service Bus — with per-topic subscription management.', bestPractice: 'Name pattern: evgd-{workload}-{env}. Use for multi-tenant SaaS; one domain contains many topics.', namingGuidance: 'Name pattern: evgd-{workload}-{env}. Use domains when you need to manage events for multiple tenants or entities through a single publish endpoint (e.g. evgd-saas-platform-prod). Topics within the domain are typically named after the tenant or entity (e.g. tenant-12345, customer-contoso). This is more efficient than managing thousands of individual custom topics.', learnUrl: 'https://learn.microsoft.com/azure/event-grid/event-domains' },
    { category: 'Integration', name: 'Event Hub namespace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=event-hubs', provider: 'Microsoft.EventHub/namespaces', abbrev: 'evhns', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Big data streaming platform ingesting millions of events per second with Kafka protocol support. Throughput units (Standard) or processing units (Premium) control capacity.', longDesc: 'Big data streaming platform capable of ingesting millions of events per second with full Apache Kafka protocol compatibility. Standard tier uses throughput units (1 TU = 1 MB/s ingress, 2 MB/s egress) while Premium tier uses processing units for dedicated compute. Features include Event Capture for automatic archival to Blob Storage or Data Lake in Avro format, Schema Registry for schema governance, and geo-disaster recovery for namespace-level failover. The Kafka endpoint enables existing Kafka producers and consumers to connect without code changes. Event retention configurable from 1-90 days (Standard) or up to unlimited (Premium).', bestPractice: 'Name pattern: evhns-{workload}-{env}. Globally unique; contains Event Hubs; enable Capture for archival.', namingGuidance: 'Name pattern: evhns-{workload}-{env}. The namespace is globally unique and forms the connection endpoint ({name}.servicebus.windows.net). Include workload and environment for clarity (e.g. evhns-telemetry-prod, evhns-clickstream-staging). Event Hubs within the namespace provide the stream-level naming. Enable Capture for production workloads to ensure event archival. Use Kafka endpoint when migrating existing Kafka workloads.', learnUrl: 'https://learn.microsoft.com/azure/event-hubs/event-hubs-about' },
    { category: 'Integration', name: 'Event Hub', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=event-hubs', provider: 'Microsoft.EventHub/namespaces/eventhubs', abbrev: 'evh', maxLength: 256, scope: 'Namespace', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Partitioned event stream with configurable retention (1-90 days) and consumer groups for parallel processing. Each partition supports up to 1 MB/sec ingress.', longDesc: 'Partitioned event stream within an Event Hub namespace, where each partition provides an ordered sequence of events with configurable retention (1-90 days in Standard, unlimited in Premium). Partitions enable parallel processing — each partition supports up to 1 MB/s ingress and 2 MB/s egress, with the partition count determining the maximum parallelism for consumers. Consumer groups provide independent views of the stream, allowing multiple consumer applications to process events at their own pace without interference. Partition keys ensure related events land in the same partition for ordered processing of a specific entity\'s events.', bestPractice: 'Name pattern: evh-{namespace}-{stream-name}. Include parent Event Hub namespace name; partition count based on parallel consumers.', namingGuidance: 'Name pattern: evh-{namespace}-{stream-name}. Name Event Hubs after the data stream they carry (e.g. evh-evhns-telemetry-device-events, evh-evhns-analytics-click-stream). Include the parent namespace for context. Set the partition count based on the number of parallel consumers you need — this cannot be increased after creation on Standard tier. Use dedicated consumer groups per consuming application.', learnUrl: 'https://learn.microsoft.com/azure/event-hubs/event-hubs-features' },
    { category: 'Integration', name: 'Logic App', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=logic-apps', provider: 'Microsoft.Logic/workflows', abbrev: 'logic', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Low-code workflow automation with 450+ connectors for SaaS, on-premises, and B2B integration. Standard tier runs on App Service for VNet integration and stateful/stateless workflows.', longDesc: 'Low-code/no-code workflow automation platform with 450+ connectors for integrating SaaS applications (Salesforce, Office 365, Dynamics), on-premises systems (via data gateway), and other Azure services. The visual designer enables complex orchestrations with conditions, loops, error handling, and parallel branches. Standard (single-tenant) runs on App Service infrastructure providing VNet integration, deployment slots, and both stateful and stateless workflow types. Supports B2B integration with AS2, X12, and EDIFACT protocols for electronic data interchange. Built-in retry policies, run history, and resubmission for operational resilience.', bestPractice: 'Name pattern: logic-{workflow}-{env}. Name by workflow purpose; use Standard for production VNet needs.', namingGuidance: 'Name pattern: logic-{workflow}-{env}. Name after the business process or integration scenario the workflow automates (e.g. logic-order-processing-prod, logic-invoice-approval-staging). Use Standard (single-tenant) for production workloads requiring VNet integration and deployment slots. For Consumption (multi-tenant) logic apps, the name reflects a single workflow, while Standard apps can contain multiple workflows.', learnUrl: 'https://learn.microsoft.com/azure/logic-apps/logic-apps-overview' },
    { category: 'Integration', name: 'Data Factory', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=data-factory', provider: 'Microsoft.DataFactory/factories', abbrev: 'adf', maxLength: 63, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Cloud ETL service with 90+ data connectors, mapping data flows for code-free transformations, and self-hosted IR for on-premises sources. Supports Git-based CI/CD.', longDesc: 'Cloud-scale ETL/ELT service with 90+ built-in data connectors for ingesting data from on-premises, cloud, and SaaS sources. Mapping Data Flows provide a code-free visual interface for data transformations running on Spark clusters. Self-hosted Integration Runtime enables secure data movement from on-premises and private network sources. SSIS Integration Runtime lifts and shifts existing SSIS packages to Azure. Pipelines support parameterisation, triggers (schedule, tumbling window, event-based), and monitoring via Azure Monitor. Git integration (Azure DevOps or GitHub) enables version control and CI/CD for data pipelines.', bestPractice: 'Name pattern: adf-{workload}-{env}. Globally unique; one per workload; enable Git integration for CI/CD.', namingGuidance: 'Name pattern: adf-{workload}-{env}. The factory name is globally unique and should reflect the data workload it serves (e.g. adf-datawarehouse-prod, adf-analytics-staging). Use one factory per workload per environment, with Git integration for version-controlled pipeline development. The dev factory publishes to a collaboration branch, and CI/CD deploys to staging/prod factories. Include environment in the name to distinguish deployment targets.', learnUrl: 'https://learn.microsoft.com/azure/data-factory/introduction' },
    { category: 'Integration', name: 'SignalR service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=signalr-service', provider: 'Microsoft.SignalRService/signalR', abbrev: 'sigr', maxLength: 63, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Real-time messaging service supporting WebSocket, Server-Sent Events, and long polling. Premium tier offers up to 1,000,000 concurrent connections per unit.', longDesc: 'Fully managed real-time messaging service providing WebSocket, Server-Sent Events, and long polling transport protocols with automatic negotiation. Handles connection management, scaling, and failover for real-time web applications. Unit-based scaling supports up to 1,000,000 concurrent connections per unit (Premium). Serverless mode integrates with Azure Functions for event-driven real-time scenarios without managing hub servers. Supports user groups and individual connection targeting for precise message delivery. Upstream webhooks enable custom authentication and message processing.', bestPractice: 'Name pattern: sigr-{workload}-{env}. Globally unique; use for real-time dashboards, chat, notifications.', namingGuidance: 'Name pattern: sigr-{workload}-{env}. The service name is globally unique and forms the endpoint ({name}.service.signalr.net). Name after the real-time feature it supports (e.g. sigr-notifications-prod, sigr-livechat-staging, sigr-dashboard-prod). Choose between Default mode (with hub server) and Serverless mode (with Azure Functions) based on architecture. Scale units based on concurrent connection requirements.', learnUrl: 'https://learn.microsoft.com/azure/azure-signalr/signalr-overview' },
    { category: 'Integration', name: 'Notification Hub', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=notification-hubs', provider: 'Microsoft.NotificationHubs/namespaces/notificationHubs', abbrev: 'ntf', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Multi-platform push notification engine for iOS, Android, Windows, and Baidu. Scales to millions of devices with tag-based routing and localized templates.', longDesc: 'Multi-platform push notification engine for iOS (APNs), Android (FCM), Windows (WNS), and Baidu. Scales to millions of device registrations with tag-based routing for targeted notifications (e.g. by user segment, location, or feature flag) and template registrations for localised messages. A Notification Hub namespace contains one or more hubs, each targeting a specific application. Supports scheduled send, direct send for urgent messages, and installation-based device management. Telemetry provides delivery statistics including success, failure, and platform-specific error codes.', bestPractice: 'Name pattern: ntf-{app}-{env}. One per app/environment; separate namespaces for isolation.', namingGuidance: 'Name pattern: ntf-{app}-{env}. Create one hub per mobile application per environment (e.g. ntf-myapp-prod, ntf-myapp-dev). The namespace groups related hubs and provides the billing boundary. Use separate namespaces for production and development to ensure complete isolation. Tag-based routing eliminates the need for individual device targeting, so plan your tag taxonomy early.', learnUrl: 'https://learn.microsoft.com/azure/notification-hubs/notification-hubs-push-notification-overview' },
    { category: 'Integration', name: 'Relay', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=service-bus', provider: 'Microsoft.Relay/namespaces', abbrev: 'relay', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Exposes on-premises services to the cloud without opening firewall ports. Supports Hybrid Connections (WebSockets) and WCF Relays.', longDesc: 'Exposes on-premises services to the cloud without requiring inbound firewall port opening or VPN infrastructure. Hybrid Connections use WebSocket-based bidirectional communication and support any language/platform, while WCF Relays provide .NET-specific integration for existing WCF services. The on-premises listener establishes an outbound connection to the Relay service, which then bridges cloud consumers to the on-premises endpoint. This is ideal for scenarios where VPN or ExpressRoute connectivity is not feasible or cost-effective. Azure App Service Hybrid Connections use this technology internally for connecting web apps to on-premises databases and APIs.', bestPractice: 'Name pattern: relay-{workload}-{env}. Use for hybrid connectivity where VPN/ExpressRoute is overkill.', namingGuidance: 'Name pattern: relay-{workload}-{env}. Use when you need to expose specific on-premises services to the cloud without the cost and complexity of VPN or ExpressRoute (e.g. relay-legacy-api-prod, relay-onprem-db-staging). For broader hybrid connectivity needs, consider VPN Gateway or ExpressRoute instead. The relay namespace is the entry point and contains individual Hybrid Connections or WCF Relays.', learnUrl: 'https://learn.microsoft.com/azure/azure-relay/relay-what-is-it' },

    // Analytics
    { category: 'Analytics', name: 'Synapse workspace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=synapse-analytics', provider: 'Microsoft.Synapse/workspaces', abbrev: 'synw', maxLength: 50, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'Unified analytics platform with dedicated/serverless SQL pools, Spark pools, and Data Explorer integration. Supports Synapse Link for real-time analytics on operational data.', longDesc: 'Unified analytics platform combining dedicated SQL pools (MPP data warehouse), serverless SQL pools (pay-per-query on data lake), Apache Spark pools for big data processing, and Data Explorer integration for log analytics. Synapse Link provides no-ETL analytical processing over Cosmos DB, Dataverse, and SQL Server data. Synapse Studio provides a unified development experience with SQL scripts, Spark notebooks, data flows, and pipeline orchestration. Managed VNet ensures all traffic between workspace components stays on the Azure backbone.', bestPractice: 'Name pattern: synw-{workload}-{env}. Globally unique; enable managed VNet for security.', namingGuidance: 'Name pattern: synw-{workload}-{env}. The workspace name is globally unique and forms the SQL endpoints ({name}.sql.azuresynapse.net and {name}-ondemand.sql.azuresynapse.net). Include workload and environment for clarity (e.g. synw-datawarehouse-prod). Enable managed VNet at creation for network isolation. The associated Data Lake Storage account should follow the dls naming convention.', learnUrl: 'https://learn.microsoft.com/azure/synapse-analytics/overview-what-is' },
    { category: 'Analytics', name: 'Synapse dedicated SQL pool', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=synapse-analytics', provider: 'Microsoft.Synapse/workspaces/sqlPools', abbrev: 'syndp', maxLength: 60, scope: 'Workspace', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Dedicated MPP data warehouse with 60 compute nodes, workload isolation, and result-set caching. Supports table partitioning, columnstore indexes, and materialized views.', longDesc: 'Dedicated Massively Parallel Processing (MPP) data warehouse with up to 60 compute nodes for high-performance analytical queries. Workload management provides resource isolation between concurrent queries using workload groups and classifiers. Result-set caching delivers instant repeated query performance. Supports table partitioning for data lifecycle management, clustered columnstore indexes for optimal compression and scan performance, and materialized views for pre-computed aggregations. Scale compute independently of storage and pause/resume to control costs during off-hours.', bestPractice: 'Name pattern: syndp-{workspace}-{purpose}. Include parent Synapse workspace name; name by data domain; pause when not in use for cost savings.', namingGuidance: 'Name pattern: syndp-{workspace}-{purpose}. Include the parent workspace name and name the pool after the data domain or purpose it serves (e.g. syndp-synw-analytics-sales, syndp-synw-dw-finance). Pause dedicated SQL pools during off-hours and weekends to save on compute costs. The storage persists independently and incurs no additional charges while paused.', learnUrl: 'https://learn.microsoft.com/azure/synapse-analytics/sql-data-warehouse/sql-data-warehouse-overview-what-is' },
    { category: 'Analytics', name: 'Data Explorer cluster', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=data-explorer', provider: 'Microsoft.Kusto/clusters', abbrev: 'dec', maxLength: 22, scope: 'Global', chars: 'a-z, 0-9', desc: 'Fast and highly scalable log and telemetry analytics engine with native KQL support. Optimized for time-series data with petabyte-scale storage and sub-second query latency.', longDesc: 'Fast and highly scalable data analytics engine optimised for real-time analysis of large volumes of streaming data including logs, telemetry, and time-series. Uses Kusto Query Language (KQL) for powerful ad-hoc queries with sub-second latency across petabytes of data. Supports ingestion from Event Hubs, IoT Hub, Azure Storage, and Kafka. Follower databases enable read-only cross-cluster queries for data sharing without duplication. Materialized views pre-compute aggregations for dashboard performance. Also available as Synapse Data Explorer and Azure Monitor Log Analytics backend.', bestPractice: 'Name pattern: dec{workload}{env}. Max 22 chars, no hyphens; use follower DBs for cross-cluster queries.', namingGuidance: 'Name pattern: dec{workload}{env}. Data Explorer cluster names are limited to 22 lowercase characters with no hyphens. Use short concatenated names (e.g. dectelemetryprod, decloganalytics). The cluster forms the endpoint ({name}.{region}.kusto.windows.net). Databases within the cluster provide granular naming. Use optimised autoscale for cost-effective scaling based on ingestion and query load.', learnUrl: 'https://learn.microsoft.com/azure/data-explorer/data-explorer-overview' },
    { category: 'Analytics', name: 'Databricks workspace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=databricks', provider: 'Microsoft.Databricks/workspaces', abbrev: 'dbw', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Unified Spark platform with Delta Lake, Unity Catalog for governance, and Photon query engine for 12x faster SQL. Premium tier offers SCIM provisioning and audit logs.', longDesc: 'Unified Spark-based analytics platform providing data engineering, data science, machine learning, and SQL analytics capabilities. Delta Lake provides ACID transactions, time travel, and schema enforcement on data lakes. Unity Catalog enables unified data governance with fine-grained access control, data lineage, and audit logging across workspaces. Photon query engine provides up to 12x faster SQL query performance. Premium tier adds Unity Catalog, SCIM provisioning, conditional access, and customer-managed keys. VNet injection deploys the workspace into your own VNet for network isolation.', bestPractice: 'Name pattern: dbw-{workload}-{env}. Use Premium for Unity Catalog governance; enable VNet injection.', namingGuidance: 'Name pattern: dbw-{workload}-{env}. Include workload and environment for clear identification (e.g. dbw-analytics-prod, dbw-ml-staging). Use Premium tier for production to enable Unity Catalog governance and audit logging. Enable VNet injection for network isolation. The workspace URL ({region}.azuredatabricks.net) is shared across workspaces in a region, so the workspace name is used for portal navigation.', learnUrl: 'https://learn.microsoft.com/azure/databricks/introduction/' },
    { category: 'Analytics', name: 'Stream Analytics Job', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=stream-analytics', provider: 'Microsoft.StreamAnalytics/streamingjobs', abbrev: 'asa', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Serverless real-time analytics engine for complex event processing (CEP) on streaming data. Integrates with Event Hubs, IoT Hub, and Blob Storage.', longDesc: 'Serverless real-time analytics engine for complex event processing (CEP) on streaming data using a SQL-like query language. Processes data from inputs (Event Hubs, IoT Hub, Blob Storage) and writes results to outputs (SQL Database, Cosmos DB, Power BI, Blob Storage, etc.). Supports windowing functions (tumbling, hopping, sliding, session) for time-based aggregations, temporal joins between streams, reference data lookups, and anomaly detection via built-in ML models. Streaming units control compute capacity with automatic scaling. Ideal for real-time dashboards, IoT analytics, and fraud detection.', bestPractice: 'Name pattern: asa-{job}-{env}. Name by job function; use for real-time dashboards and anomaly detection.', namingGuidance: 'Name pattern: asa-{job}-{env}. Name after the specific analytics function the job performs (e.g. asa-telemetry-aggregator-prod, asa-fraud-detector-staging). Configure streaming units based on expected throughput. Use CI/CD via VS Code extension or Azure DevOps for version-controlled query deployment. Consider Stream Analytics clusters for VNet-isolated production workloads.', learnUrl: 'https://learn.microsoft.com/azure/stream-analytics/stream-analytics-introduction' },
    { category: 'Analytics', name: 'Power BI Embedded', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=power-bi-embedded', provider: 'Microsoft.PowerBIDedicated/capacities', abbrev: 'pbi', maxLength: 63, scope: 'Resource group', chars: 'a-z, 0-9, -', desc: 'PaaS solution for embedding Power BI reports and dashboards into custom applications. Supports row-level security and white-labeling.', longDesc: 'PaaS solution for embedding Power BI reports, dashboards, and Q&A experiences into custom applications without requiring end users to have Power BI licences. Supports row-level security (RLS) for data-level access control, white-labelling for branded analytics, and full API control for programmatic interactions. A-series SKUs (A1-A6) provide dedicated compute for rendering reports. Integrates with Power BI service for content authoring, with embedded content served from the PaaS capacity. Supports both "App Owns Data" (for customers) and "User Owns Data" (for employees) embedding scenarios.', bestPractice: 'Name pattern: pbi-{app}-{env}. Dedicated capacity for app embedding; scale as needed.', namingGuidance: 'Name pattern: pbi-{app}-{env}. Name after the application that embeds the analytics (e.g. pbi-customerportal-prod, pbi-salesapp-staging). Scale the A-series SKU based on concurrent report rendering load. Use separate capacities for production and development to avoid rendering contention.', learnUrl: 'https://learn.microsoft.com/power-bi/developer/embedded/azure-pbi-embedded-overview' },

    // AI + Machine Learning
    { category: 'AI + ML', name: 'Machine Learning workspace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=machine-learning-service', provider: 'Microsoft.MachineLearningServices/workspaces', abbrev: 'mlw', maxLength: 33, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'End-to-end MLOps platform with automated ML, designer, notebooks, and model registry. Supports managed online endpoints with blue-green deployments and A/B testing.', longDesc: 'End-to-end MLOps platform providing automated ML (AutoML) for code-free model training, visual designer for drag-and-drop pipelines, Jupyter notebooks for interactive development, and a model registry for versioning and deployment. Managed online endpoints provide blue-green deployments, A/B testing, and autoscaling for real-time inference. Managed compute clusters auto-scale for training jobs and auto-shutdown when idle. Supports MLflow for experiment tracking, responsible AI dashboard for model fairness analysis, and pipelines for reproducible training workflows. Integrates with Azure DevOps and GitHub for MLOps CI/CD.', bestPractice: 'Name pattern: mlw-{project}-{env}. Max 33 chars. One per ML project; use managed compute for training jobs.', namingGuidance: 'Name pattern: mlw-{project}-{env}. Create one workspace per ML project or team per environment (e.g. mlw-recommendations-prod, mlw-forecasting-dev). Workspace names are limited to 33 characters. The workspace bundles associated resources (Key Vault, Storage, Container Registry, Application Insights) which should follow their respective naming conventions. Use managed compute for training to avoid infrastructure management overhead.', learnUrl: 'https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning' },
    { category: 'AI + ML', name: 'Azure AI services', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cognitive-services', provider: 'Microsoft.CognitiveServices/accounts', abbrev: 'ais', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Pre-built AI APIs for vision (OCR, face detection), speech (STT, TTS), language (translation, NER), and decision (content moderation). Supports container deployment for edge scenarios.', longDesc: 'Pre-built AI APIs covering four domains: Vision (OCR, face detection, image analysis, custom vision), Speech (speech-to-text, text-to-speech, speech translation, speaker recognition), Language (text translation, named entity recognition, sentiment analysis, question answering), and Decision (content moderator, personaliser, anomaly detector). Multi-service accounts provide a single endpoint and key for all services, while single-service accounts offer isolated keys and quotas. Supports container deployment for on-premises/edge scenarios with connected and disconnected modes. Commitment tiers provide discounted pricing for predictable volumes.', bestPractice: 'Name pattern: ais-{service}-{env}. Include service type (vision/speech/language) for clarity.', namingGuidance: 'Name pattern: ais-{service}-{env}. For single-service accounts, include the specific service type (e.g. ais-vision-prod, ais-speech-staging). For multi-service accounts, use a broader name (e.g. ais-multi-prod). Multi-service accounts simplify key management when using multiple AI services but share a single quota and billing. Use managed identity for authentication instead of API keys when possible.', learnUrl: 'https://learn.microsoft.com/azure/cognitive-services/what-are-cognitive-services' },
    { category: 'AI + ML', name: 'Azure OpenAI', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cognitive-services', provider: 'Microsoft.CognitiveServices/accounts', abbrev: 'oai', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Access to GPT-4, ChatGPT, DALL-E, and embedding models.', longDesc: 'Access to OpenAI\'s large language models (GPT-4, GPT-4o, GPT-3.5 Turbo), image generation (DALL-E 3), and embedding models (text-embedding-3) with Azure enterprise security, compliance, and regional data residency. Content filtering is enabled by default to detect and block harmful content in prompts and completions. Supports fine-tuning for customising model behaviour with your own data. Provisioned Throughput Units (PTUs) provide dedicated capacity for predictable latency and throughput. On Your Data feature enables grounded responses using your own documents via Azure AI Search integration for retrieval-augmented generation (RAG).', bestPractice: 'Name pattern: oai-{workload}-{env}. Enable content filtering; use managed identity for secure API access.', namingGuidance: 'Name pattern: oai-{workload}-{env}. Include the workload or purpose (e.g. oai-chatbot-prod, oai-copilot-staging, oai-embeddings-prod). Model deployments within the resource provide the specific model naming. Enable content filtering for all production deployments. Use managed identity for authentication and network restrictions (private endpoints) for sensitive workloads.', learnUrl: 'https://learn.microsoft.com/azure/cognitive-services/openai/overview' },
    { category: 'AI + ML', name: 'Azure AI Search', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=search', provider: 'Microsoft.Search/searchServices', abbrev: 'srch', maxLength: 60, scope: 'Global', chars: 'a-z, 0-9, -', desc: 'AI-powered search with full-text, vector, hybrid, and semantic ranking capabilities. Supports cognitive skills for document enrichment and knowledge mining.', longDesc: 'AI-powered search service providing full-text search, vector search, hybrid search (combining both), and semantic ranking for improved relevance. Cognitive skills enrich documents during indexing with AI capabilities like OCR, entity recognition, key phrase extraction, and custom ML models. Vector search enables similarity matching on embeddings from Azure OpenAI or other embedding models for retrieval-augmented generation (RAG) architectures. Supports faceted navigation, autocomplete, suggestions, and geo-spatial search. Integrated vectorisation automatically chunks and embeds documents during indexing.', bestPractice: 'Name pattern: srch-{workload}-{env}. Globally unique; use semantic ranking for improved relevance.', namingGuidance: 'Name pattern: srch-{workload}-{env}. The service name is globally unique and forms the endpoint ({name}.search.windows.net). Include workload and environment (e.g. srch-knowledge-prod, srch-ecommerce-staging). For RAG patterns with Azure OpenAI, the search service acts as the retrieval backend. Choose the tier based on index size, query volume, and feature requirements (semantic ranking requires Standard tier or above).', learnUrl: 'https://learn.microsoft.com/azure/search/search-what-is-azure-search' },
    { category: 'AI + ML', name: 'Azure Bot Service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=bot-service', provider: 'Microsoft.BotService/botServices', abbrev: 'bot', maxLength: 64, scope: 'Global', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Multi-channel bot framework supporting Teams, Slack, Web Chat, and Cortana. Integrates with LUIS, QnA Maker, and Azure OpenAI for natural language understanding.', longDesc: 'Multi-channel conversational AI platform supporting Microsoft Teams, Slack, Web Chat, Facebook Messenger, and other channels through a unified bot registration. Built on the Bot Framework SDK (C#, JavaScript, Python) with connector services for channel-specific message formatting. Integrates with Azure OpenAI for GPT-powered conversational flows, LUIS for intent recognition, and QnA Maker for FAQ-style knowledge bases. Power Virtual Agents provides a no-code alternative for building bots with a visual canvas. Bot service handles authentication, channel routing, and message delivery infrastructure.', bestPractice: 'Name pattern: bot-{purpose}-{env}. Globally unique; integrate with OpenAI for conversational AI.', namingGuidance: 'Name pattern: bot-{purpose}-{env}. Name after the bot\'s purpose or the application it serves (e.g. bot-helpdesk-prod, bot-faq-staging, bot-copilot-dev). The bot service registration is global and provides the unified endpoint for all channel connections. For conversational AI with GPT, combine with Azure OpenAI and Azure AI Search for a complete RAG-powered chatbot.', learnUrl: 'https://learn.microsoft.com/azure/bot-service/bot-service-overview' },

    // Management + Governance
    { category: 'Management + Governance', name: 'Log Analytics workspace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=monitor', provider: 'Microsoft.OperationalInsights/workspaces', abbrev: 'log', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Central repository for logs from Azure resources and apps.', longDesc: 'Central repository for log data from Azure resources, applications, and on-premises systems. Supports KQL (Kusto Query Language) for powerful ad-hoc analysis, alerting, and visualisation. Ingests data from Azure Monitor diagnostics, Application Insights, Microsoft Sentinel, and custom sources via the Data Collector API or Azure Monitor Agent. Data retention is configurable from 30 to 730 days with archive tiers for long-term compliance. Workspace-based architecture enables cross-resource queries and centralised access control via RBAC. Commitment tiers (100-5000 GB/day) provide significant cost savings over pay-as-you-go.', bestPractice: 'Name pattern: log-{purpose}-{env}-{region}. One per region typically; configure retention per compliance.', namingGuidance: 'Name pattern: log-{purpose}-{env}-{region}. The CAF recommends a centralised workspace per region for most organisations, with separate workspaces only when regulatory or access control requirements demand it (e.g. log-central-prod-uks, log-security-prod-weu). Configure retention policies per table to optimise costs. Enable commitment tiers when daily ingestion exceeds 100 GB.', learnUrl: 'https://learn.microsoft.com/azure/azure-monitor/logs/log-analytics-overview' },
    { category: 'Management + Governance', name: 'Application Insights', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=monitor', provider: 'Microsoft.Insights/components', abbrev: 'appi', maxLength: 260, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Application performance monitoring with traces and metrics.', longDesc: 'Application performance monitoring (APM) service providing distributed tracing, live metrics, request/dependency tracking, exception logging, and user behaviour analytics. Auto-instrumentation available for .NET, Java, Node.js, and Python without code changes. Smart Detection automatically identifies performance anomalies and failure patterns. Application Map visualises inter-service dependencies and their health. Workspace-based mode stores data in a Log Analytics workspace for unified querying with infrastructure logs. Availability tests monitor endpoint health from multiple global locations.', bestPractice: 'Name pattern: appi-{app}-{env}. One per app; use workspace-based mode for unified Log Analytics queries.', namingGuidance: 'Name pattern: appi-{app}-{env}. Create one Application Insights resource per application per environment (e.g. appi-payments-api-prod, appi-web-frontend-staging). Always use workspace-based mode (not classic) for unified querying with Log Analytics. Point all instances to the same centralised Log Analytics workspace for cross-application correlation and cost management.', learnUrl: 'https://learn.microsoft.com/azure/azure-monitor/app/app-insights-overview' },
    { category: 'Management + Governance', name: 'Action group', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=monitor', provider: 'Microsoft.Insights/actionGroups', abbrev: 'ag', maxLength: 260, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Notification endpoint collection for email, SMS, webhook, ITSM, Logic App, and Azure Function actions. Reusable across multiple alert rules for consistent incident response.', longDesc: 'Reusable collection of notification and automation endpoints that define who to notify and what actions to take when an alert fires. Supports email, SMS, voice call, webhook, ITSM connector (ServiceNow, BMC), Logic App, Azure Function, and Automation Runbook actions. A single action group can contain multiple action types for multi-channel incident response. Action groups are referenced by alert rules across Azure Monitor, Service Health, and Resource Health. Suppression rules can temporarily mute notifications during planned maintenance windows.', bestPractice: 'Name pattern: ag-{purpose}-{severity}. Create by severity/team; reuse across alert rules.', namingGuidance: 'Name pattern: ag-{purpose}-{severity}. Organise action groups by team and severity level (e.g. ag-platform-critical, ag-app-team-warning, ag-oncall-sev1). Reuse action groups across multiple alert rules for consistent notification behaviour. The short name (max 12 chars) appears in SMS and email subjects, so keep it descriptive but concise.', learnUrl: 'https://learn.microsoft.com/azure/azure-monitor/alerts/action-groups' },
    { category: 'Management + Governance', name: 'Automation account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=automation', provider: 'Microsoft.Automation/automationAccounts', abbrev: 'aa', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Process automation with PowerShell/Python runbooks, Update Management, and State Configuration (DSC). Supports hybrid worker for on-premises automation.', longDesc: 'Process automation platform supporting PowerShell and Python runbooks for scheduled tasks, event-driven automation, and orchestration. Update Management provides OS patch assessment and deployment for Azure VMs, on-premises servers, and multi-cloud instances. State Configuration (DSC) maintains consistent server configurations. Hybrid Runbook Workers execute runbooks on-premises or in other clouds. Supports managed identity for secure authentication, source control integration (GitHub, Azure DevOps) for runbook versioning, and integration with Azure Monitor for alerting on job failures.', bestPractice: 'Name pattern: aa-{purpose}-{env}. Use managed identity for auth; enable source control for runbooks.', namingGuidance: 'Name pattern: aa-{purpose}-{env}. Name after the automation purpose or team that owns it (e.g. aa-patching-prod, aa-infrastructure-staging). Use managed identity instead of Run As accounts (deprecated). Enable source control integration for version-controlled runbook development. For Update Management, typically one account per region is sufficient to manage all VMs in that region.', learnUrl: 'https://learn.microsoft.com/azure/automation/automation-intro' },
    { category: 'Management + Governance', name: 'Recovery Services vault', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=backup', provider: 'Microsoft.RecoveryServices/vaults', abbrev: 'rsv', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Backup and disaster recovery vault supporting Azure VMs, SQL, SAP HANA, and Azure Files. Features immutable backups, cross-region restore, and soft delete for ransomware protection.', longDesc: 'Backup and disaster recovery vault supporting Azure VMs, SQL databases (in VMs and PaaS), SAP HANA, Azure Files, and on-premises workloads via MARS/MABS agents. Immutable backup vaults prevent deletion or modification of backup data for ransomware protection. Cross-region restore enables recovery to the paired region for disaster recovery. Soft delete retains backup data for 14 additional days after deletion. Multi-user authorisation requires MFA from a second administrator for critical operations. Private endpoints ensure backup traffic flows over the Azure backbone.', bestPractice: 'Name pattern: rsv-{purpose}-{env}-{region}. One per region for backup; enable soft delete and GRS.', namingGuidance: 'Name pattern: rsv-{purpose}-{env}-{region}. Deploy one vault per region for backup workloads (e.g. rsv-backup-prod-uks, rsv-dr-prod-weu). Enable GRS (geo-redundant storage) for cross-region restore capability. Enable soft delete, immutability, and multi-user authorisation for production vaults to protect against accidental or malicious deletion of backup data.', learnUrl: 'https://learn.microsoft.com/azure/backup/backup-azure-recovery-services-vault-overview' },
    { category: 'Management + Governance', name: 'Blueprint', provider: 'Microsoft.Blueprint/blueprints', abbrev: 'bp', maxLength: 90, scope: 'Scope', chars: 'a-z, A-Z, 0-9, -, _, (), .', desc: 'Declarative environment template bundling ARM templates, policies, and RBAC assignments. Supports versioning and locking of deployed resources for governance.', longDesc: 'Declarative environment template that bundles ARM templates, Azure Policy assignments, RBAC role assignments, and resource groups into a single versioned definition. Blueprints enforce governance at scale by defining what should be deployed and what policies should be applied. Deployed resources can be locked (Do Not Delete or Read Only) to prevent drift from the blueprint definition. Supports versioning for iterative improvement and assignment tracking for audit compliance. Note: Azure Blueprints is deprecated — Microsoft recommends using Bicep templates with Azure Policy and deployment stacks for new governance implementations.', bestPractice: 'Name pattern: bp-{purpose}-{version}. Consider Bicep + Azure Policy instead; Blueprints deprecated.', namingGuidance: 'Name pattern: bp-{purpose}-{version}. Include the governance purpose and version (e.g. bp-landing-zone-v2, bp-pci-compliance-v1). Note that Azure Blueprints is deprecated — new implementations should use Bicep templates with deployment stacks and Azure Policy for equivalent functionality. If maintaining existing blueprints, use semantic versioning and document changes in each version.', learnUrl: 'https://learn.microsoft.com/azure/governance/blueprints/overview' },
    { category: 'Management + Governance', name: 'Cost Management export', provider: 'Microsoft.CostManagement/exports', abbrev: 'cme', maxLength: 64, scope: 'Scope', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Scheduled export of cost and usage data to Blob storage in CSV format. Supports amortized, actual, and usage-based cost types with daily or monthly granularity.', longDesc: 'Scheduled export of cost and usage data to Azure Blob Storage in CSV format for custom reporting and analytics. Supports amortised costs (spreading reservation charges), actual costs (as billed), and usage-based exports with daily or monthly granularity. Exports can be scoped to management groups, subscriptions, resource groups, or billing accounts. Use Power BI, Excel, or custom analytics pipelines to process exported data for chargeback, showback, and cost optimisation analysis. Focus areas include identifying idle resources, right-sizing VMs, and reservation coverage gaps.', bestPractice: 'Name pattern: cme-{scope}-{frequency}. Export to analytics storage; use Power BI for visualization.', namingGuidance: 'Name pattern: cme-{scope}-{frequency}. Include the scope and export frequency (e.g. cme-subscription-daily, cme-rg-app-monthly). Export to a dedicated analytics storage account for processing with Power BI or Azure Synapse. Create separate exports for amortised and actual costs as they serve different reporting purposes.', learnUrl: 'https://learn.microsoft.com/azure/cost-management-billing/costs/tutorial-export-acm-data' },
    { category: 'Management + Governance', name: 'Template Spec', provider: 'Microsoft.Resources/templateSpecs', abbrev: 'ts', maxLength: 90, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Resource type for storing and sharing ARM templates within an organization. Supports versioning and RBAC for secure template management.', longDesc: 'Azure resource type for storing, version-controlling, and sharing ARM/Bicep templates within an organisation through RBAC-controlled access. Template Specs are stored as Azure resources and can be deployed like any other resource, eliminating the need for external template storage (like storage accounts or Git repos) for deployment. Supports versioning with semantic version numbers, enabling rollback and audit trails. Template Specs can be referenced as linked templates in larger deployments. RBAC controls who can read, create, or deploy template specs, providing governance over infrastructure-as-code artifacts.', bestPractice: 'Name pattern: ts-{workload}-{purpose}. Store reusable ARM/Bicep modules; version semantically.', namingGuidance: 'Name pattern: ts-{workload}-{purpose}. Name after the infrastructure component the template deploys (e.g. ts-vnet-hub-spoke, ts-aks-cluster, ts-sql-server-db). Use semantic versioning (v1.0.0, v1.1.0) for versions. Store template specs in a centralised resource group accessible to all deployment pipelines. Use Bicep modules as the source format and compile to ARM for the template spec.', learnUrl: 'https://learn.microsoft.com/azure/azure-resource-manager/templates/template-specs' },

    // IoT
    { category: 'IoT', name: 'IoT Hub', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=iot-hub', provider: 'Microsoft.Devices/IotHubs', abbrev: 'iot', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Bidirectional device-to-cloud messaging platform supporting MQTT, AMQP, and HTTPS. Features device twins, direct methods, and built-in Event Hubs endpoint for telemetry routing.', longDesc: 'Bidirectional device-to-cloud messaging platform supporting MQTT 3.1.1, AMQP 1.0, and HTTPS protocols for millions of simultaneously connected IoT devices. Device twins maintain device state and metadata with optimistic concurrency. Direct methods enable synchronous command invocation on devices. Built-in Event Hubs-compatible endpoint routes telemetry to downstream processing pipelines. Message routing rules filter and direct messages to custom endpoints (Event Hubs, Service Bus, Blob Storage). File upload capability enables devices to push large data through the hub. IoT Edge extends cloud intelligence to edge devices.', bestPractice: 'Name pattern: iot-{solution}-{env}. Globally unique; use DPS for device provisioning at scale.', namingGuidance: 'Name pattern: iot-{solution}-{env}. The hub name is globally unique and forms the endpoint ({name}.azure-devices.net). Name after the IoT solution or use case (e.g. iot-fleet-tracking-prod, iot-smart-building-staging). Use IoT Hub Device Provisioning Service (DPS) for zero-touch device onboarding at scale rather than manual device registration.', learnUrl: 'https://learn.microsoft.com/azure/iot-hub/iot-concepts-and-iot-hub' },
    { category: 'IoT', name: 'Device Provisioning Service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=iot-hub', provider: 'Microsoft.Devices/provisioningServices', abbrev: 'dps', maxLength: 64, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Zero-touch device provisioning with X.509, TPM, and symmetric key attestation. Supports allocation policies for multi-hub load balancing and geographic distribution.', longDesc: 'Zero-touch, just-in-time device provisioning service that automatically registers devices to the correct IoT Hub without human intervention. Supports X.509 certificate, TPM 2.0, and symmetric key attestation methods for device authentication. Allocation policies control which IoT Hub a device is assigned to: lowest latency, evenly weighted, static configuration, or custom (via Azure Function). Enrollment groups enable bulk provisioning of devices sharing a common attestation mechanism. Re-provisioning policies handle device migration between hubs. Essential for manufacturing-time provisioning and large-scale deployments.', bestPractice: 'Name pattern: dps-{solution}-{env}. Globally unique; link to IoT Hubs for zero-touch provisioning.', namingGuidance: 'Name pattern: dps-{solution}-{env}. The DPS name is globally unique and forms the endpoint ({name}.azure-devices-provisioning.net). Align naming with the IoT Hub it provisions devices to (e.g. dps-fleet-tracking-prod linked to iot-fleet-tracking-prod). A single DPS instance can provision devices across multiple linked IoT Hubs using allocation policies.', learnUrl: 'https://learn.microsoft.com/azure/iot-dps/about-iot-dps' },
    { category: 'IoT', name: 'Digital Twins', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=digital-twins', provider: 'Microsoft.DigitalTwins/digitalTwinsInstances', abbrev: 'dt', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Live digital model of physical environments with DTDL ontology, graph queries, and event routing. Enables simulation, analytics, and integration with Time Series Insights.', longDesc: 'Live digital representation of physical environments, assets, and processes using Digital Twin Definition Language (DTDL) ontologies. Models physical entities as a graph with properties, relationships, and telemetry. Supports graph queries (SQL-like) for traversing relationships and finding twins matching specific criteria. Event routes push twin change notifications to downstream services (Event Hubs, Event Grid, Service Bus) for real-time processing. Integrates with Azure Maps for spatial intelligence and 3D Scenes Studio for visual representation. Common use cases include smart buildings, manufacturing digital twins, and supply chain modelling.', bestPractice: 'Name pattern: dt-{solution}-{env}. Model with DTDL ontology; route events to Functions for processing.', namingGuidance: 'Name pattern: dt-{solution}-{env}. Name after the physical environment or system being modelled (e.g. dt-building-mgmt-prod, dt-factory-floor-staging). The DTDL models define the ontology and should be version-controlled separately. Event routes to Event Grid or Event Hubs enable reactive processing of twin state changes.', learnUrl: 'https://learn.microsoft.com/azure/digital-twins/overview' },

    // Desktop Virtualization
    { category: 'Desktop Virtualization', name: 'Host Pool', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-desktop', provider: 'Microsoft.DesktopVirtualization/hostPools', abbrev: 'vdpool', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Collection of Azure Virtual Desktop session hosts. Supports pooled (multi-session) or personal (single-session) assignment types.', longDesc: 'Collection of Azure Virtual Desktop session hosts that serve as the compute layer for user sessions. Pooled host pools use multi-session Windows 11/10 Enterprise or Windows Server images for shared desktop or RemoteApp delivery, with load balancing (breadth-first or depth-first) distributing users across available hosts. Personal host pools assign dedicated VMs to individual users for persistent desktop experiences. Session hosts can be Azure VMs or Azure Stack HCI machines. RDP properties control clipboard, drive, and printer redirection policies for security.', bestPractice: 'Name pattern: vdpool-{workload}-{env}-{region}. Group hosts by workload type.', namingGuidance: 'Name pattern: vdpool-{workload}-{env}-{region}. Name after the user group or workload type the pool serves (e.g. vdpool-developers-prod-uks, vdpool-callcenter-prod-weu). Use pooled type for shared desktops and personal type for power users. Include region since host pools are regional resources. Session host VMs within the pool follow their own naming convention.', learnUrl: 'https://learn.microsoft.com/azure/virtual-desktop/host-pool-load-balancing' },
    { category: 'Desktop Virtualization', name: 'Application Group', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-desktop', provider: 'Microsoft.DesktopVirtualization/applicationGroups', abbrev: 'vdag', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Logical grouping of applications installed on session hosts. Can be a Desktop application group (full desktop) or RemoteApp application group (individual apps).', longDesc: 'Logical grouping of applications installed on session hosts that determines what users can access. Each host pool has a default Desktop application group created automatically for full desktop access. RemoteApp application groups publish individual applications (e.g. Excel, SAP, LOB apps) that appear in the user\'s Start menu or feed. Users can be assigned to multiple RemoteApp application groups across different host pools, but can only access one Desktop application group. Application groups are assigned to Azure AD security groups for access control.', bestPractice: 'Name pattern: vdag-{hostpool}-{type}. Include parent host pool name; type can be desktop or remoteapp.', namingGuidance: 'Name pattern: vdag-{hostpool}-{type}. Include the parent host pool name and the type of application group (e.g. vdag-developers-desktop, vdag-callcenter-remoteapp-office, vdag-finance-remoteapp-sap). For RemoteApp groups, include the application set being published to distinguish between multiple groups on the same host pool.', learnUrl: 'https://learn.microsoft.com/azure/virtual-desktop/environment-setup' },
    { category: 'Desktop Virtualization', name: 'Workspace', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-desktop', provider: 'Microsoft.DesktopVirtualization/workspaces', abbrev: 'vdws', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Logical grouping of application groups in Azure Virtual Desktop. This is what users subscribe to in their feed.', longDesc: 'Logical grouping of application groups that determines what appears in a user\'s Azure Virtual Desktop feed (the list of available desktops and applications). Users subscribe to workspaces via the Remote Desktop client or web client and see all application groups within their assigned workspace. A workspace can contain application groups from multiple host pools, enabling a unified view of all available resources. Workspace names are user-facing and appear in the client UI, so they should be meaningful and descriptive for end users.', bestPractice: 'Name pattern: vdws-{workload}-{env}-{region}. One workspace can contain multiple app groups.', namingGuidance: 'Name pattern: vdws-{workload}-{env}-{region}. Since workspace names are visible to end users in the Remote Desktop client, use descriptive, user-friendly names (e.g. vdws-engineering-prod-uks, vdws-finance-prod-weu). One workspace per department or business unit is a common pattern. Register multiple application groups from different host pools within the same workspace for a unified user experience.', learnUrl: 'https://learn.microsoft.com/azure/virtual-desktop/environment-setup' },
    { category: 'Desktop Virtualization', name: 'Scaling Plan', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=virtual-desktop', provider: 'Microsoft.DesktopVirtualization/scalingPlans', abbrev: 'vdscaling', maxLength: 64, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Autoscaling rules for pooled host pools to optimize costs. Defines ramp-up, peak, ramp-down, and off-peak schedules.', longDesc: 'Autoscaling configuration for pooled host pools that automatically starts and stops session hosts based on predefined schedules and capacity thresholds to optimise costs. Defines four phases: ramp-up (gradually start hosts before peak), peak (maintain capacity), ramp-down (gracefully drain and stop hosts), and off-peak (minimal capacity). Each phase has configurable capacity thresholds, load balancing algorithms, and minimum host counts. Scaling plans use time zone-aware schedules and can be assigned to multiple host pools with the same usage pattern. Supports drain mode for graceful session migration during scale-down.', bestPractice: 'Name pattern: vdscaling-{pool}-{schedule}. Link to specific host pools and schedules.', namingGuidance: 'Name pattern: vdscaling-{pool}-{schedule}. Include the target host pool and schedule type (e.g. vdscaling-developers-weekday, vdscaling-callcenter-24x7). Align scaling phases with actual work patterns — analyse sign-in data from Log Analytics to determine optimal ramp-up and ramp-down times. Set minimum host percentages for off-peak to ensure some capacity is always available for early/late users.', learnUrl: 'https://learn.microsoft.com/azure/virtual-desktop/autoscale-scaling-plan' },

    // DevOps
    { category: 'DevOps', name: 'DevOps organization', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=azure-devops', provider: 'Microsoft.VisualStudio/account', abbrev: 'ado', maxLength: 50, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Azure DevOps tenant with Repos (Git), Boards (Agile planning), Pipelines (CI/CD), Test Plans, and Artifacts. Supports Microsoft Entra ID integration and audit streaming.', longDesc: 'Azure DevOps organisation providing a unified platform for software development with five integrated services: Repos (Git version control), Boards (Agile project management with Scrum, Kanban, and CMMI process templates), Pipelines (CI/CD with YAML or classic pipelines, 1,800 free minutes/month for public projects), Test Plans (manual and exploratory testing), and Artifacts (NuGet, npm, Maven, Python package feeds). Microsoft Entra ID integration enables SSO, conditional access, and centralised user lifecycle management. Audit streaming sends compliance events to Splunk, Azure Monitor, or Event Grid.', bestPractice: 'Name pattern: ado-{org}. Globally unique; connect to Entra ID; use project-level permissions.', namingGuidance: 'Name pattern: ado-{org}. The organisation name is globally unique and forms the URL ({name}.visualstudio.com and dev.azure.com/{name}). Typically one organisation per company or division. Use projects within the organisation for team or product separation (e.g. ado-contoso with projects for each product team). Connect to Microsoft Entra ID immediately after creation for centralised identity management. Note that underscores are not permitted in organisation names. This tool automatically uses your provided organisation prefix (or falls back to the workload name) to generate this resource name, overriding the standard environment and region segments.', learnUrl: 'https://learn.microsoft.com/azure/devops/user-guide/what-is-azure-devops' },
    { category: 'DevOps', name: 'DevTest Labs', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=devtest-lab', provider: 'Microsoft.DevTestLab/labs', abbrev: 'dtl', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Self-service sandbox for creating VMs and PaaS resources with quotas, auto-shutdown, and claimable pools. Ideal for dev/test scenarios with cost controls.', longDesc: 'Self-service sandbox environment for creating VMs and PaaS resources with built-in cost controls including per-user VM quotas, auto-shutdown schedules, and auto-start policies. Claimable VM pools provide pre-provisioned development machines that team members can claim and release without administrator involvement. Custom images and formulas enable standardised, reproducible environments. Artifact-based configuration applies tools and settings during VM creation. Integrates with Azure DevOps for CI/CD pipeline-driven environment creation. Cost management features include per-lab spending limits and cost trend analysis.', bestPractice: 'Name pattern: dtl-{team}-{purpose}. Enable auto-shutdown; use claimable VMs for shared dev pool.', namingGuidance: 'Name pattern: dtl-{team}-{purpose}. Name after the team or project using the lab (e.g. dtl-platform-dev, dtl-qa-testing). Enable auto-shutdown on all VMs to prevent runaway costs. Use claimable VM pools for shared development resources. Create custom images for standardised development environments that include required tools and configurations.', learnUrl: 'https://learn.microsoft.com/azure/devtest-labs/devtest-lab-overview' },

    // AI + ML
    { category: 'AI + ML', name: 'Microsoft Foundry resource', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cognitive-services', provider: 'Microsoft.CognitiveServices/accounts', abbrev: 'aif', maxLength: 64, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Top-level container for Azure AI services providing unified billing, access control, and endpoint management.', longDesc: 'Microsoft Foundry resource is the top-level container handling security, networking, and billing for your AI workloads. It provides a unified identity and access control boundary, allowing you to manage access to language, vision, speech, and generative AI capabilities through a single resource instead of provisioning individual service endpoints.', bestPractice: 'Name pattern: aif-{workload}-{env}. Globally unique. Note: Overwrite the Azure Portal default name to follow CAF.', namingGuidance: 'Name pattern: aif-{workload}-{env}. The Azure Portal may automatically append "-resource" to the parent project name. It is recommended to overwrite this default and apply the standard "aif" abbreviation to adhere to CAF naming conventions. The name forms your endpoint URL so it must be globally unique.', learnUrl: 'https://learn.microsoft.com/azure/ai-services/what-are-ai-services' },
    { category: 'AI + ML', name: 'Microsoft Foundry hub', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=machine-learning-service', provider: 'Microsoft.MachineLearningServices/workspaces', abbrev: 'hub', maxLength: 33, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Central workspace for AI teams to organize projects, share managed network configurations, and centralize compute.', longDesc: 'Microsoft Foundry hub is a secure boundary for managing shared resources across multiple AI projects. It centralizes network isolation, compute clusters, and storage connections, allowing enterprise IT to configure security once while data scientists self-serve AI projects within that secure boundary.', bestPractice: 'Name pattern: hub-{workload}-{env}. Share across related AI projects within a workload.', namingGuidance: 'Name pattern: hub-{workload}-{env}. The hub handles network isolation for child projects. Ensure it is deployed with a Managed Virtual Network (vNet) and private endpoints enabled to secure model training data and prevent data exfiltration.', learnUrl: 'https://learn.microsoft.com/azure/ai-studio/concepts/architecture' },
    { category: 'AI + ML', name: 'Microsoft Foundry project', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=machine-learning-service', provider: 'Microsoft.MachineLearningServices/workspaces', abbrev: 'proj', maxLength: 33, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Dedicated workspace within an AI Foundry hub or account for building, evaluating, and deploying AI agents and models.', longDesc: 'Microsoft Foundry project is a logical container within a Foundry resource used to group related models, agents, prompt flows, and evaluation datasets. It inherits the security boundary, network isolation, and compute resources from its parent hub or account while providing an isolated environment for a specific application or use case.', bestPractice: 'Name pattern: proj-{appname}-{env}. Name after the specific application or use case.', namingGuidance: 'Name pattern: proj-{appname}-{env}. The project inherits security boundaries from its parent. Use role-based access control (RBAC) to grant developers the "Azure AI Developer" role scoped specifically to the project level rather than the hub.', learnUrl: 'https://learn.microsoft.com/azure/ai-studio/how-to/create-projects' },
    { category: 'AI + ML', name: 'Foundry IQ', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=machine-learning-service', provider: 'Microsoft.MachineLearningServices/workspaces', abbrev: 'fiq', maxLength: 33, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Knowledge layer and context engineering platform to ground AI agents in organizational data.', longDesc: 'Foundry IQ is a managed knowledge layer and context engineering platform within the Microsoft Foundry ecosystem. It connects to internal and external data stores to provide agentic retrieval, synthesizing results and providing citations while enforcing enterprise security and permissions.', bestPractice: 'Name pattern: fiq-{workload}-{env}. Use for knowledge bases grounding AI agents.', namingGuidance: 'Name pattern: fiq-{workload}-{env}. Provisioned conceptually as a knowledge base or connection within a Machine Learning workspace. There is no standalone Foundry IQ Azure resource provider, so the naming applies to the associated workspace or connection resource.', learnUrl: 'https://learn.microsoft.com/azure/ai-studio/concepts/architecture' },
    { category: 'AI + ML', name: 'Azure AI services account', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cognitive-services', provider: 'Microsoft.CognitiveServices/accounts', abbrev: 'ais', maxLength: 64, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Multi-service account providing access to Azure AI capabilities including Vision, Language, Speech, and Decision.', longDesc: 'Azure AI services account (multi-service account) provides a single endpoint and API key to access multiple Azure AI capabilities without needing to provision individual service resources. This simplifies development and unified billing.', bestPractice: 'Name pattern: ais-{workload}-{env}. Globally unique; preferred over individual service accounts.', namingGuidance: 'Name pattern: ais-{workload}-{env}. Name must be globally unique. Must start and end with an alphanumeric character.', learnUrl: 'https://learn.microsoft.com/azure/ai-services/multi-service-resource' },
    { category: 'AI + ML', name: 'Azure OpenAI service', pricingUrl: 'https://azure.microsoft.com/pricing/calculator/?service=cognitive-services', provider: 'Microsoft.CognitiveServices/accounts', abbrev: 'oai', maxLength: 64, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Provides REST API access to OpenAI\'s powerful language models including GPT-4, GPT-3.5-Turbo, and Embeddings series.', longDesc: 'Azure OpenAI service provides enterprise-grade access to OpenAI\'s powerful language models with built-in Azure security, compliance, and regional availability. Supports fine-tuning, private networking via Private Link, and integration with Azure AI Search for RAG (Retrieval-Augmented Generation) patterns.', bestPractice: 'Name pattern: oai-{workload}-{env}. Globally unique; use Private Link for enterprise workloads.', namingGuidance: 'Name pattern: oai-{workload}-{env}. Name must be globally unique as it forms the custom subdomain endpoint.', learnUrl: 'https://learn.microsoft.com/azure/ai-services/openai/overview' },

    // Additional Services
    { category: 'Integration', name: 'App Configuration store', provider: 'Microsoft.AppConfiguration/configurationStores', abbrev: 'appcs', maxLength: 50, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Managed service that helps developers centralize their application and feature settings simply and securely.', longDesc: 'Azure App Configuration provides a service to centrally manage application settings and feature flags. Modern programs, especially those running in a cloud, generally have many components that are distributed in nature. Spreading configuration settings across these components can lead to hard-to-troubleshoot errors during an application deployment. App Configuration enables you to store all the settings for your application and secure their accesses in one place.', bestPractice: 'Name pattern: appcs-{workload}-{env}-{region}. Use standard naming convention.', namingGuidance: 'Name pattern: appcs-{workload}-{env}-{region}. Needs to be unique within a resource group. Note that the Azure Portal sometimes limits creation rules differently, but the CAF suggests appending standard suffixes.', learnUrl: 'https://learn.microsoft.com/azure/azure-app-configuration/overview' },
    { category: 'Management & Governance', name: 'Azure Managed Grafana', provider: 'Microsoft.Dashboard/grafana', abbrev: 'amg', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Fully managed service for analytics and monitoring solutions natively integrated with Azure Monitor.', longDesc: 'Azure Managed Grafana is a data visualization platform built on top of the Grafana software by Grafana Labs. It\'s built as a fully managed Azure service operated and supported by Microsoft. Grafana helps you bring together metrics, logs and traces into a single user interface. With its extensive support for data sources and graphing capabilities, you can view and analyze your application and infrastructure telemetry data in real-time.', bestPractice: 'Name pattern: amg-{workload}-{env}-{region}. Enable Managed Identity for seamless Azure Monitor access.', namingGuidance: 'Name pattern: amg-{workload}-{env}-{region}. Name must be globally unique across Azure, as it defines the endpoint URL.', learnUrl: 'https://learn.microsoft.com/azure/managed-grafana/overview' },
    { category: 'Data & AI', name: 'Microsoft Purview instance', provider: 'Microsoft.Purview/accounts', abbrev: 'pview', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Unified data governance service that helps you manage and govern your on-premises, multicloud, and software-as-a-service (SaaS) data.', longDesc: 'Microsoft Purview provides a unified data governance solution to help manage and govern your on-premises, multi-cloud, and software-as-a-service (SaaS) data. Create a holistic, up-to-date map of your data landscape with automated data discovery, sensitive data classification, and end-to-end data lineage. Enable data consumers to find valuable, trustworthy data.', bestPractice: 'Name pattern: pview-{workload}-{env}-{region}. Use Managed Identity for data scanning authentication.', namingGuidance: 'Name pattern: pview-{workload}-{env}-{region}. Name must be globally unique. Hyphens are permitted. Purview accounts are typically deployed per enterprise or major business unit rather than per workload.', learnUrl: 'https://learn.microsoft.com/azure/purview/overview' },
    { category: 'Web', name: 'Web PubSub', provider: 'Microsoft.SignalRService/webPubSub', abbrev: 'wps', maxLength: 63, scope: 'Global', chars: 'a-z, A-Z, 0-9, -', desc: 'Fully managed service that enables using WebSockets and the publish-subscribe pattern to build real-time web applications.', longDesc: 'Azure Web PubSub Service is a fully managed service that helps you build real-time messaging web applications using WebSockets and the publish-subscribe pattern. It allows you to broadcast real-time messages to millions of users without having to manage the underlying infrastructure. It can be easily integrated with Azure Functions.', bestPractice: 'Name pattern: wps-{workload}-{env}-{region}. Use for WebSocket-based real-time features.', namingGuidance: 'Name pattern: wps-{workload}-{env}-{region}. The resource name must be globally unique as it is used to generate the public DNS endpoint. Alphanumeric and hyphens only.', learnUrl: 'https://learn.microsoft.com/azure/azure-web-pubsub/overview' },
    { category: 'Networking', name: 'Network interface', provider: 'Microsoft.Network/networkInterfaces', abbrev: 'nic', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _, .', desc: 'Enables an Azure Virtual Machine to communicate with internet, Azure, and on-premises resources.', longDesc: 'A network interface (NIC) is the interconnection between a Virtual Machine and a virtual network. A virtual machine must have at least one network interface, but can have more than one depending on the size of the VM. Each NIC is assigned a dynamic or static private IP address and can be associated with a public IP address, a Network Security Group (NSG), or an Application Security Group (ASG).', bestPractice: 'Name pattern: nic-{vmname}-{index}. Keep names aligned with the parent VM.', namingGuidance: 'Name pattern: nic-{vmname}-{index}. Automatically generated when deploying a VM via the portal, but should be explicitly named when using IaC to ensure consistency (e.g. nic-vmw-prod-app-01).', learnUrl: 'https://learn.microsoft.com/azure/virtual-network/virtual-network-network-interface' },
    { category: 'Databases', name: 'Azure Managed Redis', provider: 'Microsoft.Cache/redisEnterprise', abbrev: 'amr', maxLength: 63, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Fully managed, enterprise-grade Redis service providing high availability, data persistence, and active geo-replication.', longDesc: 'Azure Managed Redis (formerly Enterprise tiers of Azure Cache for Redis) provides access to the Redis Enterprise software as a fully managed Azure service. It offers active geo-replication, higher availability (up to 99.999%), Redis modules like RediSearch and RedisJSON, and is optimized for maximum performance. This is the recommended tier for mission-critical Redis workloads.', bestPractice: 'Name pattern: amr-{workload}-{env}-{region}. Globally unique endpoint.', namingGuidance: 'Name pattern: amr-{workload}-{env}-{region}. The name must be globally unique. Replaces the standard `redis` abbreviation for enterprise deployments.', learnUrl: 'https://learn.microsoft.com/azure/azure-cache-for-redis/cache-overview' },
    { category: 'Networking', name: 'DNS private resolver', provider: 'Microsoft.Network/dnsResolvers', abbrev: 'dnspr', maxLength: 80, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -, _', desc: 'Fully managed service that enables querying Azure DNS private zones from an on-premises environment and vice versa.', longDesc: 'Azure DNS Private Resolver is a fully managed service that enables querying Azure DNS private zones from an on-premises environment and vice versa without deploying VM-based DNS servers. It handles conditional forwarding and DNS resolution transparently via inbound and outbound endpoints connected to your Virtual Network.', bestPractice: 'Name pattern: dnspr-{hub}-{region}. Deploy in hub network for centralized DNS resolution.', namingGuidance: 'Name pattern: dnspr-{hub}-{region}. Typically deployed centrally in a hub Virtual Network. Inbound and outbound endpoints have their own specific naming (in, out).', learnUrl: 'https://learn.microsoft.com/azure/dns/dns-private-resolver-overview' },
    { category: 'Integration', name: 'API Center service', provider: 'Microsoft.ApiCenter/services', abbrev: 'apic', maxLength: 90, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Centralized registry to discover, manage, and govern APIs across your organization.', longDesc: 'Azure API Center provides a centralized hub where you can keep track of all your APIs in a single place. It allows API developers and managers to catalog their APIs regardless of their type, lifecycle stage, or deployment location, helping to reduce duplication and improve discoverability.', bestPractice: 'Name pattern: apic-{workload}-{env}-{region}. Use as a centralized catalog across teams.', namingGuidance: 'Name pattern: apic-{workload}-{env}-{region}. Name must be unique within the resource group.', learnUrl: 'https://learn.microsoft.com/azure/api-center/overview' },
    { category: 'DevOps', name: 'Managed DevOps Pools', provider: 'Microsoft.DevOpsInfrastructure/pools', abbrev: 'mdp', maxLength: 90, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Managed platform for hosting Azure DevOps agent pools with built-in auto-scaling and pre-configured images.', longDesc: 'Managed DevOps Pools provide a fully managed infrastructure for your Azure DevOps self-hosted agents. It simplifies the setup of scalable build agents by handling the underlying VM scale sets, auto-scaling rules, and image updates. You can quickly deploy pools with specific configurations to meet compliance and performance requirements without the overhead of manual VM management.', bestPractice: 'Name pattern: mdp-{team}-{purpose}. Use for scalable CI/CD runners.', namingGuidance: 'Name pattern: mdp-{team}-{purpose}. Name should reflect the team or specific pipeline purpose (e.g. mdp-platform-linux, mdp-windows-build).', learnUrl: 'https://learn.microsoft.com/azure/devops/managed-devops-pools/overview' },
    { category: 'Compute', name: 'Service Fabric cluster', provider: 'Microsoft.ServiceFabric/clusters', abbrev: 'sf', maxLength: 60, scope: 'Resource group', chars: 'a-z, A-Z, 0-9, -', desc: 'Distributed systems platform that makes it easy to package, deploy, and manage scalable and reliable microservices.', longDesc: 'Azure Service Fabric is a distributed systems platform that makes it easy to package, deploy, and manage scalable and reliable microservices and containers. Service Fabric also addresses the significant challenges in developing and managing cloud native applications. Developers and administrators can avoid complex infrastructure problems and focus on implementing mission-critical, demanding workloads that are scalable, reliable, and manageable.', bestPractice: 'Name pattern: sf-{workload}-{env}-{region}. Recommended for existing workloads; prefer AKS/Container Apps for new containerized apps.', namingGuidance: 'Name pattern: sf-{workload}-{env}-{region}. The cluster name forms part of the Azure-provided fully qualified domain name (FQDN), and must be globally unique.', learnUrl: 'https://learn.microsoft.com/azure/service-fabric/service-fabric-overview' }
];

